/* ============================================================
   ATLAS — glossary of key terms (term, def, topic).
   topic = a course id, or "general".
   ============================================================ */
window.GLOSSARY = [
  // ---- linear algebra ----
  { term: "Vector", topic: "linear-algebra", def: "An ordered list of numbers (a point/arrow in $\\mathbb{R}^n$) that can be added and scaled. The atom of linear algebra." },
  { term: "Span", topic: "linear-algebra", def: "The set of all linear combinations of a set of vectors — every point you can reach by scaling and adding them." },
  { term: "Linear independence", topic: "linear-algebra", def: "A set of vectors where none is a combination of the others; the only way to combine them to $\\mathbf{0}$ is with all-zero coefficients." },
  { term: "Basis", topic: "linear-algebra", def: "A minimal set of vectors that spans a space (independent + spanning). Its size is the dimension." },
  { term: "Rank", topic: "linear-algebra", def: "The number of linearly independent columns (= rows) of a matrix; the dimension of its column space." },
  { term: "Determinant", topic: "linear-algebra", def: "A scalar measuring how a matrix scales area/volume; zero means the map collapses dimensions and isn't invertible." },
  { term: "Eigenvector / eigenvalue", topic: "linear-algebra", def: "A vector $\\mathbf{v}$ with $A\\mathbf{v}=\\lambda\\mathbf{v}$: the matrix only stretches it by $\\lambda$, never rotates it off its line." },
  { term: "SVD", topic: "linear-algebra", def: "Singular Value Decomposition $A=U\\Sigma V^\\top$: factors any matrix into rotation · scaling · rotation; the basis of low-rank approximation and PCA." },
  // ---- calculus ----
  { term: "Limit", topic: "calculus", def: "The value a function approaches as its input nears a point — the foundation of derivatives and integrals." },
  { term: "Derivative", topic: "calculus", def: "The instantaneous rate of change of a function; the slope of its tangent line, $f'(x)=\\lim_{h\\to0}\\frac{f(x+h)-f(x)}{h}$." },
  { term: "Chain rule", topic: "calculus", def: "$\\frac{d}{dx}f(g(x))=f'(g(x))g'(x)$ — differentiates composed functions. The engine of backpropagation." },
  { term: "Gradient", topic: "calculus", def: "The vector of partial derivatives $\\nabla f$; points in the direction of steepest ascent of a multivariable function." },
  { term: "Partial derivative", topic: "calculus", def: "The rate of change of a multivariable function as you nudge one variable, holding the rest fixed." },
  { term: "Integral", topic: "calculus", def: "Accumulated area under a curve; the inverse operation to differentiation (Fundamental Theorem of Calculus)." },
  { term: "Hessian", topic: "calculus", def: "The matrix of second partial derivatives; its eigenvalues reveal whether a critical point is a min, max, or saddle." },
  { term: "Taylor approximation", topic: "calculus", def: "Approximating a function near a point by a polynomial built from its derivatives; the linear case is the tangent line." },
  // ---- algorithms ----
  { term: "Big-O", topic: "algorithms", def: "Asymptotic upper bound on how an algorithm's cost grows with input size $n$, ignoring constants and lower-order terms." },
  { term: "Recurrence", topic: "algorithms", def: "An equation defining a quantity in terms of smaller inputs, e.g. $T(n)=2T(n/2)+\\Theta(n)$; solved with the Master Theorem." },
  { term: "Dynamic programming", topic: "algorithms", def: "Solving a problem by combining solutions to overlapping subproblems, each computed once and reused (memoized)." },
  { term: "Greedy algorithm", topic: "algorithms", def: "Builds a solution by always taking the locally best choice; optimal only when the problem has the right (matroid-like) structure." },
  { term: "Hash table", topic: "algorithms", def: "A structure giving average $O(1)$ insert/lookup/delete by mapping keys to buckets via a hash function." },
  { term: "BFS / DFS", topic: "algorithms", def: "Graph traversals: breadth-first explores level by level (a queue); depth-first goes deep first (a stack/recursion)." },
  { term: "Divide and conquer", topic: "algorithms", def: "Split a problem into subproblems, solve recursively, and combine — e.g. mergesort, binary search." },
  { term: "NP-complete", topic: "algorithms", def: "The hardest problems in NP: verifiable in polynomial time, and any NP problem reduces to them; no known efficient solution." },
  // ---- deep learning ----
  { term: "Neuron / perceptron", topic: "deep-learning", def: "A unit computing a weighted sum of inputs plus a bias, then a nonlinear activation: $\\sigma(\\mathbf{w}^\\top\\mathbf{x}+b)$." },
  { term: "Activation function", topic: "deep-learning", def: "The nonlinearity (ReLU, sigmoid, tanh) applied per neuron; without it, stacked layers collapse to one linear map." },
  { term: "Backpropagation", topic: "deep-learning", def: "Computing loss gradients for every weight by applying the chain rule backward through the network, reusing forward-pass values." },
  { term: "Gradient descent", topic: "deep-learning", def: "Iteratively updating parameters opposite the gradient, $\\theta\\leftarrow\\theta-\\eta\\nabla L$, to minimize a loss." },
  { term: "Loss function", topic: "deep-learning", def: "Measures prediction error to minimize: MSE for regression, cross-entropy for classification." },
  { term: "Overfitting", topic: "deep-learning", def: "When a model memorizes training data and generalizes poorly; countered by regularization, dropout, and more data." },
  { term: "Regularization", topic: "deep-learning", def: "Techniques (L2/weight decay, dropout, early stopping) that discourage complexity to improve generalization." },
  { term: "Convolution", topic: "deep-learning", def: "Sliding a small learnable kernel over an input to produce a feature map; the core of CNNs, exploiting locality and weight sharing." },
  // ---- reinforcement learning ----
  { term: "MDP", topic: "reinforcement-learning", def: "Markov Decision Process $(S,A,P,R,\\gamma)$: the formalism for sequential decisions where the future depends only on the current state." },
  { term: "Policy", topic: "reinforcement-learning", def: "The agent's strategy $\\pi(a\\mid s)$: which action to take in each state." },
  { term: "Value function", topic: "reinforcement-learning", def: "Expected long-term return from a state ($V$) or state-action pair ($Q$) under a policy." },
  { term: "Bellman equation", topic: "reinforcement-learning", def: "The recursive consistency relation $Q(s,a)=r+\\gamma\\max_{a'}Q(s',a')$: value now = reward + discounted future value." },
  { term: "Q-learning", topic: "reinforcement-learning", def: "A model-free, off-policy method that learns optimal action-values from sampled transitions via the TD error." },
  { term: "Reward", topic: "reinforcement-learning", def: "The scalar feedback signal the agent seeks to maximize over time; the only supervision in RL." },
  { term: "Discount factor", topic: "reinforcement-learning", def: "$\\gamma\\in[0,1)$ weighting future rewards vs immediate ones; keeps infinite-horizon returns finite." },
  { term: "Exploration vs exploitation", topic: "reinforcement-learning", def: "The tradeoff between trying new actions to learn and using known-good ones to earn; e.g. $\\varepsilon$-greedy." },
  // ---- LLMs ----
  { term: "Token", topic: "llm", def: "A subword chunk of text (via BPE) — the unit a language model reads and predicts." },
  { term: "Embedding", topic: "llm", def: "A learned high-dimensional vector for a token; semantically similar tokens lie near each other, so meaning becomes geometry." },
  { term: "Attention", topic: "llm", def: "A mechanism letting each token gather information from others, weighted by relevance: $\\text{softmax}(QK^\\top/\\sqrt{d_k})V$." },
  { term: "Transformer", topic: "llm", def: "The architecture of stacked attention + feed-forward blocks with residuals; processes all tokens in parallel." },
  { term: "Softmax", topic: "llm", def: "Turns a vector of scores into a probability distribution (positive, summing to 1); used for next-token output and attention weights." },
  { term: "Pretraining", topic: "llm", def: "Training a model on massive text via next-token prediction to learn general language and world structure before any task tuning." },
  { term: "Fine-tuning", topic: "llm", def: "Adapting a pretrained model to a task or style with further training (e.g. instruction tuning / SFT, or efficient LoRA)." },
  { term: "RLHF", topic: "llm", def: "Reinforcement Learning from Human Feedback: aligning a model to preferences via a reward model (or directly, with DPO)." },
  // ---- probability & statistics ----
  { term: "Probability", topic: "probability-statistics", def: "A number in $[0,1]$ measuring how likely an event is; the whole sample space has probability 1 (Kolmogorov's axioms)." },
  { term: "Conditional probability", topic: "probability-statistics", def: "$P(A\\mid B)=\\frac{P(A\\cap B)}{P(B)}$ — the probability of $A$ once you know $B$ happened; zoom into $B$ and renormalize." },
  { term: "Bayes' theorem", topic: "probability-statistics", def: "$P(H\\mid E)=\\frac{P(E\\mid H)P(H)}{P(E)}$ — flips a conditional; posterior $\\propto$ likelihood $\\times$ prior. The engine of belief updating." },
  { term: "Independence (events)", topic: "probability-statistics", def: "$A,B$ are independent if $P(A\\cap B)=P(A)P(B)$ — knowing one tells you nothing about the other (NOT the same as mutually exclusive)." },
  { term: "Random variable", topic: "probability-statistics", def: "A function assigning a number to each outcome; described by a distribution (PMF if discrete, PDF if continuous)." },
  { term: "Expectation", topic: "probability-statistics", def: "The long-run average $\\mathbb{E}[X]=\\sum x\\,p(x)$ (or $\\int x f(x)\\,dx$); the probability-weighted mean. Linear: $\\mathbb{E}[aX+bY]=a\\mathbb{E}[X]+b\\mathbb{E}[Y]$." },
  { term: "Variance", topic: "probability-statistics", def: "$\\operatorname{Var}(X)=\\mathbb{E}[(X-\\mu)^2]=\\mathbb{E}[X^2]-\\mu^2$ — the average squared spread; its square root is the standard deviation." },
  { term: "Normal distribution", topic: "probability-statistics", def: "The bell curve $N(\\mu,\\sigma^2)$; the 68–95–99.7 rule gives the mass within 1/2/3 std devs. Ubiquitous via the CLT." },
  { term: "Central Limit Theorem", topic: "probability-statistics", def: "The sample mean of many i.i.d. variables is approximately normal, $\\bar X\\approx N(\\mu,\\sigma^2/n)$ — whatever the original distribution." },
  { term: "Law of Large Numbers", topic: "probability-statistics", def: "The sample mean converges to the true expectation as $n\\to\\infty$ — why averages stabilize and Monte Carlo works." },
  { term: "Covariance / correlation", topic: "probability-statistics", def: "$\\operatorname{Cov}(X,Y)=\\mathbb{E}[XY]-\\mathbb{E}[X]\\mathbb{E}[Y]$ measures linear co-movement; correlation $\\rho=\\operatorname{Cov}/(\\sigma_X\\sigma_Y)\\in[-1,1]$ rescales it." },
  { term: "Standard error", topic: "probability-statistics", def: "The standard deviation of an estimator; for the sample mean it is $\\sigma/\\sqrt{n}$ — precision improves only as $\\sqrt{n}$." },
  { term: "Confidence interval", topic: "probability-statistics", def: "A data-built range (e.g. $\\bar X\\pm z^*\\sigma/\\sqrt n$) from a procedure that captures the true parameter a set fraction (e.g. 95%) of the time — a property of the method, not one interval." },
  { term: "p-value", topic: "probability-statistics", def: "The probability, assuming the null is true, of data at least as extreme as observed. Reject when $p\\le\\alpha$. NOT the probability the null is true." },
  { term: "Hypothesis test", topic: "probability-statistics", def: "A procedure pitting a skeptical null $H_0$ against an alternative; compute a test statistic and reject $H_0$ only if the data are too extreme under it." },
  { term: "Estimator / bias", topic: "probability-statistics", def: "A statistic used to guess a parameter; its bias is $\\mathbb{E}[\\hat\\theta]-\\theta$. $\\operatorname{MSE}=\\operatorname{Var}+\\operatorname{Bias}^2$ — unbiased isn't always best." },
  // ---- advanced terms across the six ----
  { term: "Jacobian", topic: "linear-algebra", def: "The $m\\times n$ matrix of all first partials of a vector function $\\mathbf{f}:\\mathbb{R}^n\\to\\mathbb{R}^m$; its transpose pulls gradients backward (the heart of backprop)." },
  { term: "Convex function", topic: "calculus", def: "A 'bowl' where the chord lies above the graph ($f''\\ge0$ / PSD Hessian); its key gift: every local minimum is global, so optimization is reliable." },
  { term: "Lagrange multiplier", topic: "calculus", def: "$\\lambda$ in $\\nabla f=\\lambda\\nabla g$ — solves 'optimize $f$ subject to $g=0$' (contours tangent to the constraint); $\\lambda$ is the constraint's shadow price." },
  { term: "Amortized analysis", topic: "algorithms", def: "The average cost per operation over a worst-case sequence (a guarantee, not probability) — e.g. a doubling dynamic array is $O(1)$ amortized per append." },
  { term: "Max-flow / min-cut", topic: "algorithms", def: "The maximum flow through a capacitated network equals the minimum cut capacity; found by augmenting paths (Ford–Fulkerson / Edmonds–Karp)." },
  { term: "Union-Find", topic: "algorithms", def: "A disjoint-set structure with find + union; with path compression and union by rank, near-constant $O(\\alpha(n))$ amortized. Powers Kruskal's MST." },
  { term: "Autoencoder / VAE", topic: "deep-learning", def: "An encoder→bottleneck→decoder that reconstructs its input; a VAE makes the latent probabilistic (ELBO + reparameterization trick) so you can sample new data." },
  { term: "GAN", topic: "deep-learning", def: "Generative Adversarial Network: a generator and discriminator in a minimax game; the generator learns to produce realistic samples by fooling the discriminator." },
  { term: "Diffusion model", topic: "deep-learning", def: "A generator that learns to reverse a gradual noising process — train by predicting added noise, then denoise pure noise into a sample. Powers DALL·E, Stable Diffusion." },
  { term: "Policy gradient", topic: "reinforcement-learning", def: "Directly optimize a parameterized policy by ascending $\\nabla_\\theta\\,\\mathbb{E}[\\text{return}]$; the basis of REINFORCE, actor-critic, and PPO." },
  { term: "Model-based RL", topic: "reinforcement-learning", def: "Learn a model of the dynamics $\\hat p(s'\\mid s,a)$ and reward, then plan against it (Dyna, MCTS) — far more sample-efficient, but limited by model error." },
  // ---- added iter 176: high-frequency ML/DL/RL terms missing from the inline tooltips ----
  { term: "Cross-entropy", topic: "deep-learning", def: "The standard classification loss $-\\sum_k y_k\\log\\hat y_k$ — the negative log-likelihood of a categorical distribution; with a one-hot label it is just $-\\log\\hat y_c$, the surprise at the true class." },
  { term: "KL divergence", topic: "deep-learning", def: "$D_{\\mathrm{KL}}(p\\Vert q)$ measures how one distribution differs from another; non-negative, zero iff $p=q$, and asymmetric. It is the VAE's latent regularizer and underlies the cross-entropy objective." },
  { term: "Learning rate", topic: "deep-learning", def: "The step-size scalar $\\eta$ in gradient descent $\\theta\\leftarrow\\theta-\\eta\\nabla L$ — the single most important hyperparameter; too high diverges, too low crawls." },
  { term: "Dropout", topic: "deep-learning", def: "A regularizer that randomly zeros each unit with probability $p$ on every training pass (a different thinned sub-network each time); off at test time. Discourages fragile co-adaptation." },
  { term: "Batch normalization", topic: "deep-learning", def: "Normalizes a layer's pre-activations to ~zero-mean/unit-variance over the minibatch, then applies a learned scale $\\gamma$ and shift $\\beta$; smooths the loss landscape so you can train deeper, faster." },
  { term: "Layer normalization", topic: "deep-learning", def: "Like batch norm but normalizes across a single example's features instead of across the batch — batch-independent with identical train/test behavior, which is why transformers use it." },
  { term: "Logit", topic: "deep-learning", def: "A raw, unnormalized score from the final linear layer, before softmax/sigmoid turns it into a probability. Losses like cross-entropy are most stable computed directly from logits." },
  { term: "Epoch", topic: "deep-learning", def: "One full pass over the entire training set. A step (iteration) is one update from one batch; with $N$ examples and batch size $B$ there are $\\lceil N/B\\rceil$ steps per epoch." },
  { term: "Receptive field", topic: "deep-learning", def: "The region of the input that influences a given unit's activation. Stacking convolutions or increasing stride enlarges it, letting deep layers 'see' more context." },
  { term: "Gradient clipping", topic: "deep-learning", def: "Capping the gradient's norm (clip-by-global-norm) before an update to prevent exploding gradients — a standard stabilizer for RNNs and deep nets." },
  { term: "Mixed precision", topic: "deep-learning", def: "Running most computation in a lower-precision float (bfloat16/float16) instead of float32 to speed up matmuls and cut memory, keeping a few sensitive parts in 32-bit." },
  { term: "Maximum likelihood", topic: "general", def: "Choosing parameters that make the observed data most probable — maximize $\\sum_i\\log p_\\theta(x_i)$. MSE (Gaussian noise) and cross-entropy (categorical) are both maximum-likelihood losses in disguise." },
  { term: "Perplexity", topic: "llm", def: "The exponential of the average cross-entropy, $e^{H}$ — roughly 'how many equally-likely choices the model is torn between' per token. Lower is better; it is the standard language-model metric." },
  { term: "Markov property", topic: "reinforcement-learning", def: "The future depends only on the current state and action, not on the full history of how you got there. It is what lets a policy depend only on the current state." },
  // ---- added iter 239: deepen the inline glossary (LLM, linear algebra, calculus) ----
  { term: "Positional encoding", topic: "llm", def: "Information about token order added to embeddings, since self-attention is otherwise order-blind. Classic transformers add fixed sinusoids of many frequencies; modern models often use rotary embeddings (RoPE)." },
  { term: "KV cache", topic: "llm", def: "At inference, the keys and values computed for past tokens are stored and reused so each new token costs $O(n)$ work instead of recomputing the whole sequence — why causal attention makes generation linear per token." },
  { term: "Beam search", topic: "llm", def: "A decoding strategy that keeps the $k$ most-probable partial sequences (beams) at each step instead of committing to one — often higher-quality than greedy for short, high-precision outputs." },
  { term: "Nucleus sampling", topic: "llm", def: "Top-$p$ decoding: sample only from the smallest set of tokens whose probabilities sum to $p$, truncating the unreliable tail. Adapts the candidate set to the model's confidence, unlike fixed top-$k$." },
  { term: "Greedy decoding", topic: "llm", def: "Always emit the single highest-probability next token. Fast and deterministic, but myopic — it can paint itself into low-probability corners that beam search or sampling avoid." },
  { term: "In-context learning", topic: "llm", def: "A model's ability to perform a new task purely from examples in the prompt, with no weight updates — an emergent property of large-scale pretraining." },
  { term: "Chain-of-thought", topic: "llm", def: "Prompting a model to produce intermediate reasoning steps before its final answer, which markedly improves performance on multi-step problems." },
  { term: "Scaling laws", topic: "llm", def: "Empirical power-law relationships showing test loss falls predictably as model size, data, and compute grow — the basis for compute-optimal model sizing (Chinchilla)." },
  { term: "LoRA", topic: "llm", def: "Low-Rank Adaptation: freeze the pretrained weights and train only small low-rank update matrices, cutting fine-tuning memory and storage by orders of magnitude with little quality loss." },
  { term: "Quantization", topic: "llm", def: "Storing and computing weights and activations in fewer bits (int8, int4) to shrink memory and speed up inference, trading a little accuracy for large efficiency gains." },
  { term: "Retrieval-augmented generation", topic: "llm", def: "RAG: fetch relevant documents from an external store and condition generation on them, grounding answers in up-to-date sources and reducing hallucination." },
  { term: "Hallucination", topic: "llm", def: "When a language model produces fluent, confident text that is factually wrong or unsupported — a consequence of optimizing for plausible continuations, not truth." },
  { term: "Autoregressive", topic: "llm", def: "Generating a sequence one token at a time, each conditioned on all previous ones: $p(x)=\\prod_t p(x_t \\mid x_{1:t-1})$. The factorization behind GPT-style models." },
  { term: "Dot product", topic: "linear-algebra", def: "$\\mathbf{a}\\cdot\\mathbf{b}=\\sum_i a_i b_i=\\lVert a\\rVert\\,\\lVert b\\rVert\\cos\\theta$ — the scalar measuring how much two vectors point the same way; zero exactly when they are orthogonal. The basis of projection and cosine similarity." },
  { term: "Orthogonality", topic: "linear-algebra", def: "Two vectors are orthogonal (perpendicular) when their dot product is zero. Orthogonal directions carry independent information — the idea behind orthonormal bases, QR, and PCA." },
  { term: "Projection", topic: "linear-algebra", def: "The shadow of one vector onto another (or onto a subspace): the closest point in that subspace, with the error vector orthogonal to it. The geometry behind least squares." },
  { term: "Linear transformation", topic: "linear-algebra", def: "A map $T$ with $T(ax+by)=aT(x)+bT(y)$ — equivalently, multiplication by a matrix. It sends lines to lines and fixes the origin." },
  { term: "Column space", topic: "linear-algebra", def: "The span of a matrix's columns: all vectors reachable as $Ax$. The system $Ax=b$ is solvable exactly when $b$ lies in the column space." },
  { term: "Null space", topic: "linear-algebra", def: "All solutions of $Ax=0$. Its dimension (the nullity) plus the rank equals the number of columns — the rank-nullity theorem." },
  { term: "Diagonalization", topic: "linear-algebra", def: "Writing $A=PDP^{-1}$ with $D$ diagonal (the eigenvalues) and $P$ its eigenvectors — turning matrix powers and exponentials into elementwise operations." },
  { term: "Orthonormal basis", topic: "linear-algebra", def: "A basis of mutually orthogonal unit vectors. Coordinates become simple dot products and the change-of-basis matrix is orthogonal ($Q^{-1}=Q^\\top$); Gram-Schmidt builds one." },
  { term: "Positive definite", topic: "linear-algebra", def: "A symmetric matrix with $x^\\top A x>0$ for every nonzero $x$ — all eigenvalues positive. Characterizes convex quadratic bowls and valid covariance matrices." },
  { term: "Continuity", topic: "calculus", def: "A function is continuous at a point if its limit there equals its value — no jumps, holes, or blow-ups. A prerequisite for differentiability." },
  { term: "Critical point", topic: "calculus", def: "Where the derivative (or gradient) is zero or undefined — the candidates for maxima, minima, and saddle points." },
  { term: "Saddle point", topic: "calculus", def: "A critical point that is a minimum along one direction and a maximum along another (indefinite Hessian) — neither peak nor valley, and a key obstacle in optimization." },
  { term: "Directional derivative", topic: "calculus", def: "The rate of change of a function along a chosen unit direction $u$: $\\nabla f\\cdot u$. It is largest along the gradient, which is why the gradient is the steepest-ascent direction." },
  { term: "Riemann sum", topic: "calculus", def: "Approximating a definite integral as a sum of rectangle areas; as the partition is refined the sum converges to the exact area under the curve." },
  { term: "Fundamental theorem of calculus", topic: "calculus", def: "Differentiation and integration are inverses: $\\frac{d}{dx}\\int_a^x f(t)\\,dt=f(x)$, and $\\int_a^b f=F(b)-F(a)$ for any antiderivative $F$." },
  // ---- added iter 257: deepen the inline glossary (algorithms, reinforcement learning) ----
  { term: "Binary search", topic: "algorithms", def: "Find a target in a sorted array by halving the search window each step — $O(\\log n)$. Requires sorted input, and underlies the broader 'binary-search-the-answer' technique." },
  { term: "Recursion", topic: "algorithms", def: "A function defined in terms of itself, reducing a problem to smaller instances until a base case. The natural shape of divide-and-conquer, tree traversal, and backtracking." },
  { term: "Memoization", topic: "algorithms", def: "Caching each distinct subproblem's result so it is computed once — the top-down face of dynamic programming, turning exponential recomputation into linear work." },
  { term: "Binary search tree", topic: "algorithms", def: "A tree keeping left $<$ node $<$ right, so search, insert, and delete are $O(h)$; kept balanced (AVL, red-black) that is $O(\\log n)$, but a degenerate BST decays to a linked list." },
  { term: "Heap", topic: "algorithms", def: "A complete binary tree with the heap property (each parent $\\le$ its children, for a min-heap): $O(\\log n)$ insert and extract-min. The engine behind priority queues and heapsort." },
  { term: "Topological sort", topic: "algorithms", def: "A linear ordering of a DAG's vertices so every edge points forward — the valid order to run tasks with dependencies. It exists if and only if the graph is acyclic." },
  { term: "Shortest path", topic: "algorithms", def: "The minimum-weight route between vertices. Dijkstra solves it for non-negative weights (a greedy frontier), Bellman-Ford tolerates negative edges, and BFS handles unweighted graphs." },
  { term: "Loop invariant", topic: "algorithms", def: "A condition true before and after every iteration of a loop; proving it holds (plus termination) proves the algorithm correct — the backbone of correctness arguments." },
  { term: "Discounted return", topic: "reinforcement-learning", def: "$G_t = \\sum_{k} \\gamma^k r_{t+k}$, the discounted sum of future rewards — the quantity an RL agent actually maximizes. Value functions are its expectation." },
  { term: "Temporal-difference learning", topic: "reinforcement-learning", def: "Updating a value estimate toward a bootstrapped target $r + \\gamma V(s')$ — learning from the next step without waiting for the episode to end. The bridge between Monte Carlo and dynamic programming." },
  { term: "SARSA", topic: "reinforcement-learning", def: "On-policy TD control using the action actually taken next: $Q(s,a) \\leftarrow Q(s,a) + \\alpha[r + \\gamma Q(s',a') - Q(s,a)]$. It learns the value of the policy it follows (unlike off-policy Q-learning)." },
  { term: "Advantage function", topic: "reinforcement-learning", def: "$A(s,a) = Q(s,a) - V(s)$: how much better an action is than the state's average. Centering policy-gradient updates on it sharply cuts their variance." },
  { term: "Actor-critic", topic: "reinforcement-learning", def: "Combine a policy (actor) with a learned value function (critic) that supplies a low-variance baseline/advantage — the practical middle ground between pure policy gradients and pure value methods." },
  { term: "Off-policy", topic: "reinforcement-learning", def: "Learning about a different (typically greedy) policy than the one generating the data — what lets Q-learning and DQN reuse stored experience. On-policy methods (SARSA) learn the policy they follow." },
  { term: "Experience replay", topic: "reinforcement-learning", def: "Storing past transitions and sampling them in random minibatches — breaks the correlation between consecutive samples and reuses data many times. A key DQN stabilizer." },
  { term: "Eligibility trace", topic: "reinforcement-learning", def: "A short-term memory of recently visited states that decays by $\\gamma\\lambda$, letting a single reward update many preceding states at once — the mechanism behind TD($\\lambda$)." },
  { term: "Prior", topic: "probability-statistics", def: "In Bayesian inference, the distribution $p(\\theta)$ over a parameter before any data is seen — your starting belief. Bayes' theorem combines it with the likelihood to produce the posterior." },
  { term: "Posterior", topic: "probability-statistics", def: "The updated distribution $p(\\theta \\mid x)$ over a parameter after incorporating data, via Bayes' theorem: $p(\\theta \\mid x) \\propto p(x \\mid \\theta)\\,p(\\theta)$ — likelihood times prior." },
  { term: "Expected value", topic: "probability-statistics", def: "The probability-weighted average of a random variable, $\\mathbb{E}[X]=\\sum_x x\\,p(x)$ (an integral for continuous $X$) — its long-run mean over many draws. Also called the expectation." },
  { term: "Stationary distribution", topic: "reinforcement-learning", def: "For a Markov chain, a distribution $\\pi$ left unchanged by the transition: $\\pi = \\pi P$. It is the long-run fraction of time spent in each state, independent of where you started." },
  { term: "Taylor series", topic: "calculus", def: "An exact representation of a smooth function as an infinite sum of its derivatives at a point: $f(x)=\\sum_{n=0}^{\\infty}\\frac{f^{(n)}(a)}{n!}(x-a)^n$. Truncating it gives the Taylor-polynomial approximation." },
  // ---- iter 397 additions ----
  { term: "ReLU", topic: "deep-learning", def: "The rectified linear unit $\\text{ReLU}(x) = \\max(0, x)$ — the default activation: cheap, non-saturating for positive inputs, and sparse (it zeroes negatives), which keeps gradients flowing in deep nets." },
  { term: "Momentum", topic: "deep-learning", def: "A gradient-descent accelerator that adds a fraction of the previous update to the current one, building velocity along consistent directions and damping the oscillations that slow plain SGD across a ravine." },
  { term: "Adam", topic: "deep-learning", def: "An adaptive optimizer combining momentum (a running mean of the gradient) with RMSProp (dividing by a running root-mean-square of the gradient), plus bias correction — robust to scale and the default for training neural nets." },
  { term: "Vanishing gradient", topic: "deep-learning", def: "When gradients shrink toward zero as they backpropagate through many layers or time-steps (repeated multiplication by factors $\\lt 1$), so early layers barely learn — the problem residual connections, ReLUs, and LSTMs were built to fix." },
  { term: "Residual connection", topic: "deep-learning", def: "A skip path that adds a block's input to its output, $y = x + f(x)$, giving gradients a direct route backward and letting very deep networks train — the backbone of ResNets and Transformers." },
  { term: "Batch / mini-batch", topic: "deep-learning", def: "The subset of training examples used to compute one gradient estimate; mini-batches trade the noise of single examples against the cost of the full dataset, and map naturally onto GPU parallelism." },
  { term: "Temperature", topic: "llm", def: "A softmax knob $T$ that rescales logits before sampling: $T \\lt 1$ sharpens the distribution (more deterministic), $T \\gt 1$ flattens it (more random), and $T \\to 0$ recovers greedy/argmax decoding." },
  { term: "Self-attention", topic: "llm", def: "Attention where the queries, keys, and values all come from the same sequence, letting every token mix in information from every other token — the core token-mixing operation of a Transformer block." },
  { term: "Monte Carlo method", topic: "probability-statistics", def: "Estimating a quantity by averaging many random samples; the estimate converges to the true value with error shrinking like $1/\\sqrt{n}$ — used for integration, simulation, and reinforcement-learning value estimation." },
  { term: "Entropy", topic: "probability-statistics", def: "The average surprise of a distribution, $H = -\\sum_i p_i \\log p_i$ — maximal for the uniform distribution, zero for a certain outcome; it measures uncertainty and lower-bounds the bits needed to encode samples." },
  { term: "Spectral theorem", topic: "linear-algebra", def: "Every real symmetric matrix has real eigenvalues and an orthonormal eigenbasis, so $A = Q \\Lambda Q^\\top$ — it acts as a pure stretch along perpendicular axes." },
  { term: "Condition number", topic: "linear-algebra", def: "The ratio of a matrix's largest to smallest singular value; a large value means it nearly collapses some direction, making linear systems sensitive to error and gradient descent slow (it zig-zags across mismatched curvatures)." },
  { term: "Graph", topic: "algorithms", def: "A set of nodes (vertices) joined by edges, modeling networks and relationships; traversed by BFS/DFS and the substrate for shortest-path, max-flow, and connectivity algorithms." },
  // ---- machine learning ----
  { term: "k-Nearest Neighbors (kNN)", topic: "machine-learning", def: "A lazy, nonparametric classifier: to label a point, find its $k$ closest training examples (by some distance) and take their majority vote. No training beyond storing the data." },
  { term: "Decision tree", topic: "machine-learning", def: "A model that predicts by following a flowchart of yes/no feature tests from root to leaf. Splits are axis-aligned; grown greedily by reducing node impurity." },
  { term: "Gini impurity", topic: "machine-learning", def: "A measure of node mixedness used to choose tree splits: $G=1-\\sum_i p_i^2$, the chance of mislabeling a sample drawn by the node's class frequencies. Zero when pure." },
  { term: "Linear regression", topic: "machine-learning", def: "Predicts a number as a weighted sum of features, $\\hat{y}=w^\\top x+b$, fit by minimizing mean squared error (least squares). The atom of supervised learning." },
  { term: "Logistic regression", topic: "machine-learning", def: "A linear classifier that squashes a linear score through the sigmoid $\\sigma(z)=1/(1+e^{-z})$ to output a probability; trained with cross-entropy. A single neuron." },
  { term: "Ridge & Lasso", topic: "machine-learning", def: "Regularized linear regression: ridge adds an L2 penalty $\\lambda\\sum w_j^2$ (smooth shrinkage); lasso adds an L1 penalty $\\lambda\\sum|w_j|$ (drives weights to exactly zero — feature selection)." },
  { term: "Support Vector Machine (SVM)", topic: "machine-learning", def: "A classifier that picks the maximum-margin separating hyperplane, defined by a few support vectors. Equivalent to hinge loss + L2; kernelizable for nonlinear boundaries." },
  { term: "Kernel trick", topic: "machine-learning", def: "Compute the dot product in a high- (even infinite-) dimensional feature space directly via a kernel $k(x,z)$, without ever forming the features — giving nonlinear boundaries cheaply (e.g. the RBF kernel)." },
  { term: "Naive Bayes", topic: "machine-learning", def: "A probabilistic classifier applying Bayes' rule with the 'naive' assumption that features are conditionally independent given the class, so training is just counting. Strong, fast text baseline." },
  { term: "k-Means", topic: "machine-learning", def: "Unsupervised clustering: alternately assign points to the nearest of $k$ centroids and move each centroid to its cluster's mean (Lloyd's algorithm), minimizing within-cluster variance." },
  { term: "Bias-variance tradeoff", topic: "machine-learning", def: "Total error splits into bias (error from too-simple assumptions, underfitting) and variance (sensitivity to the training data, overfitting). Model complexity trades one for the other." },
  { term: "Ensemble learning", topic: "machine-learning", def: "Combining many models so their errors cancel. Bagging (e.g. random forests) averages independent models to cut variance; boosting builds models sequentially to cut bias." },
  { term: "Random forest", topic: "machine-learning", def: "A bagged ensemble of decision trees that also picks a random feature subset at each split, decorrelating the trees so averaging reduces variance much further. A robust default." },
  { term: "Gradient boosting", topic: "machine-learning", def: "An ensemble that builds trees sequentially, each fit to the negative gradient (residuals) of the loss so far, added with a small learning rate — gradient descent in function space. XGBoost/LightGBM dominate tabular ML." },
  { term: "Cross-validation", topic: "machine-learning", def: "Estimating generalization by splitting data into $k$ folds, training on $k-1$ and validating on the held-out fold in rotation, then averaging. Used to tune hyperparameters without touching the test set." },
  { term: "Precision & recall", topic: "machine-learning", def: "Precision = fraction of positive predictions that are correct; recall = fraction of actual positives caught. They trade off via the decision threshold; F1 is their harmonic mean. Vital on imbalanced data, where accuracy misleads." },
  { term: "ROC curve / AUC", topic: "machine-learning", def: "The ROC curve plots true-positive vs false-positive rate across all thresholds; its area (AUC) is the probability the model ranks a random positive above a random negative — a threshold-free measure of ranking quality." },
  { term: "Antiderivative", topic: "calculus", def: "A function $F$ whose derivative is $f$ (so $F'=f$); the indefinite integral $\\int f\\,dx=F+C$. It reverses differentiation, but unlike differentiation has no general algorithm — most functions have no elementary antiderivative." },
  { term: "L'Hôpital's rule", topic: "calculus", def: "For a $0/0$ or $\\infty/\\infty$ limit, $\\lim \\frac{f}{g}=\\lim\\frac{f'}{g'}$ under mild conditions — replace a ratio of functions by the ratio of their slopes to resolve an indeterminate form." },
  { term: "Linear approximation", topic: "calculus", def: "Approximating a function near a point by its tangent line: $f(x)\\approx f(a)+f'(a)(x-a)$. The first-order Taylor term and the basis of Newton's method and \"local linearity.\"" },
  { term: "Newton's method", topic: "calculus", def: "A root-finder that repeatedly replaces the curve with its tangent line: $x_{n+1}=x_n-f(x_n)/f'(x_n)$. Converges quadratically near a simple root; the optimization cousin uses the second derivative." },
  { term: "Differential equation", topic: "calculus", def: "An equation relating a function to its derivatives, e.g. $\\frac{dy}{dx}=f(x,y)$. Models how things change; most are solved numerically (Euler, Runge–Kutta) because closed-form solutions are rare." },
  { term: "Implicit differentiation", topic: "calculus", def: "Differentiating an equation that defines $y$ implicitly (not solved for $y$) by applying $\\frac{d}{dx}$ to both sides and using the chain rule on $y$. How related-rates and inverse-function derivatives are found." },
  { term: "Extreme Value Theorem", topic: "calculus", def: "A continuous function on a closed, bounded interval attains a maximum and a minimum. The existence guarantee that makes \"find the optimum\" a well-posed problem." },
  { term: "Intermediate Value Theorem", topic: "calculus", def: "A continuous function on $[a,b]$ takes every value between $f(a)$ and $f(b)$; if those straddle zero, a root lies in between. The basis of the bisection method." },
  { term: "Indeterminate form", topic: "calculus", def: "An expression like $0/0$, $\\infty-\\infty$, or $1^\\infty$ whose limit is not fixed by the parts alone — a question, not an answer, resolved by L'Hôpital, algebra, or a series." },
  { term: "Squeeze theorem", topic: "calculus", def: "If $g\\le f\\le h$ near a point and $g,h\\to L$, then $f\\to L$. Traps a hard (often oscillating) limit between two easy ones; it is how $\\lim_{x\\to 0}\\frac{\\sin x}{x}=1$ is proved." },
  { term: "Euler's method", topic: "calculus", def: "The simplest numerical ODE solver: step along the slope field, $y_{n+1}=y_n+h\\,f(x_n,y_n)$. Crude (error per step $\\sim h^2$); Runge–Kutta is the accurate default." },
  { term: "Improper integral", topic: "calculus", def: "An integral with an infinite limit or an unbounded integrand, defined as a limit, e.g. $\\int_0^\\infty e^{-x}\\,dx=1$. The native form of probability normalizations, expectations, and transforms." },
  { term: "Inflection point", topic: "calculus", def: "A point where a curve's concavity flips (the second derivative changes sign) — where the slope is steepest or shallowest, e.g. the center of a sigmoid." },
  { term: "Self-information", topic: "information-theory", def: "$I(x)=-\\log p(x)$, the \"surprisal\" of an outcome — small for likely events, large for rare ones. Entropy is its expectation." },
  { term: "Mutual information", topic: "information-theory", def: "$I(X;Y)=\\sum p(x,y)\\log\\frac{p(x,y)}{p(x)\\,p(y)}$ — the bits one variable reveals about another. Zero iff independent; a general measure of dependence beyond linear correlation." },
  { term: "Bit (information)", topic: "information-theory", def: "The unit of information from a base-2 logarithm: the information in a fair coin flip, or one optimal yes/no question. Base $e$ instead gives nats." },
  { term: "Nat", topic: "information-theory", def: "The unit of information from the natural logarithm ($\\ln$); $1$ nat $=\\log_2 e\\approx 1.44$ bits. The default unit in machine learning, because $\\ln$ has clean derivatives." },
  { term: "Information gain", topic: "information-theory", def: "The drop in entropy from splitting on a feature, $H(\\text{parent})-\\sum \\tfrac{n_k}{n}H(\\text{child}_k)$. Decision trees split on the feature with the highest gain." },
  { term: "Maximum entropy principle", topic: "information-theory", def: "When choosing a distribution under constraints, pick the highest-entropy one — it assumes the least beyond what is known. Fixing mean and variance yields the Gaussian." },
  { term: "Channel capacity", topic: "information-theory", def: "The maximum mutual information between a channel's input and output, $C=\\max_{p(x)} I(X;Y)$ — the highest rate (bits per use) at which information can be sent with vanishing error (Shannon)." },
  { term: "Source coding theorem", topic: "information-theory", def: "Shannon's result that a source of entropy $H$ needs at least $H$ bits per symbol to encode losslessly, and can get arbitrarily close — entropy is the hard limit of compression." },
  { term: "Differential entropy", topic: "information-theory", def: "$h(X)=-\\int f(x)\\log f(x)\\,dx$ — the continuous analogue of entropy. It can be negative and depends on the units of $x$, but its differences (KL divergence, mutual information) stay well-defined. The Gaussian maximizes it for a fixed variance." },
  { term: "Information bottleneck", topic: "information-theory", def: "A principle that a good representation $T$ of input $X$ should maximize $I(T;Y)$ (keep label-relevant information) while minimizing $I(T;X)$ (compress away the rest) — framing generalization as compression." },
  { term: "Soft actor-critic", topic: "reinforcement-learning", def: "An off-policy actor-critic method that adds a (differential) entropy bonus to the reward, so the policy earns return while staying as random as possible — maximum-entropy RL, which improves exploration and robustness." },
  { term: "Supervised learning", topic: "machine-learning", def: "Learning a mapping from inputs to outputs using labeled examples (features + target). Classification (discrete labels) and regression (continuous) are its two kinds." },
  { term: "Unsupervised learning", topic: "machine-learning", def: "Finding structure in unlabeled data — clusters, low-dimensional representations, density — with no target to predict. k-means and PCA are classic examples." },
  { term: "Feature", topic: "machine-learning", def: "An individual measurable input variable (a column of the data) a model uses to predict — a pixel, a word count, an age. Feature engineering crafts good ones." },
  { term: "Label", topic: "machine-learning", def: "The target a supervised model learns to predict — the class or number attached to each training example (the \"right answer\")." },
  { term: "Hyperparameter", topic: "machine-learning", def: "A configuration set before training (learning rate, tree depth, $k$ in kNN, regularization strength $\\lambda$) — chosen by validation, not learned from the data like model parameters." },
  { term: "Underfitting", topic: "machine-learning", def: "When a model is too simple to capture the pattern — high bias, poor on both training and test data. The opposite of overfitting; fix with a more expressive model or better features." },
  { term: "One-hot encoding", topic: "machine-learning", def: "Representing a categorical value as a vector of all zeros except a single 1 at the category index — so unordered categories carry no false numeric ordering." },
  { term: "Bootstrap", topic: "machine-learning", def: "Resampling a dataset with replacement to build many pseudo-datasets — the basis of bagging (random forests) and of bootstrap confidence intervals." },
  { term: "Tensor", topic: "deep-learning", def: "A multi-dimensional array of numbers — scalar (0-D), vector (1-D), matrix (2-D), or higher. The basic data structure flowing through a neural network." },
  { term: "Sigmoid", topic: "deep-learning", def: "The logistic function $\\sigma(z)=\\dfrac{1}{1+e^{-z}}$, squashing any real number into the range $0$ to $1$ — used for probabilities and as a smooth gate." },
  { term: "Transfer learning", topic: "deep-learning", def: "Reusing a model pretrained on a large task as the starting point for a related one — fine-tuning its general features instead of training from scratch." },
  { term: "Tokenization", topic: "llm", def: "Splitting raw text into the discrete units (tokens, often subwords) a language model actually reads; byte-pair encoding (BPE) is the common scheme." },
  { term: "Poisson distribution", topic: "probability-statistics", def: "$P(X=k)=e^{-\\lambda}\\lambda^k/k!$ — the count of independent events in a fixed interval at average rate $\\lambda$. Uniquely, mean = variance = $\\lambda$; it is the binomial limit for rare events." },
  { term: "Exponential distribution", topic: "probability-statistics", def: "$f(x)=\\lambda e^{-\\lambda x}$ on $[0,\\infty)$ — the waiting time between Poisson events. It is memoryless, with mean $1/\\lambda$." },
  { term: "Uniform distribution", topic: "probability-statistics", def: "Constant density on an interval $[a,b]$ — every value equally likely. Models pure ignorance; mean $(a+b)/2$." },
  { term: "Binomial distribution", topic: "probability-statistics", def: "$P(X=k)=\\binom{n}{k}p^k(1-p)^{n-k}$ — the number of successes in $n$ independent trials each with success probability $p$. Mean $np$, variance $np(1-p)$." },
  { term: "Geometric distribution", topic: "probability-statistics", def: "$P(X=k)=(1-p)^{k-1}p$ — the number of trials until the first success. The discrete memoryless wait; mean $1/p$." },
  { term: "Bernoulli distribution", topic: "probability-statistics", def: "A single trial that is 1 with probability $p$ or 0 otherwise — the building block of the binomial. Mean $p$, variance $p(1-p)$." },
  { term: "Memorylessness", topic: "probability-statistics", def: "A waiting distribution where elapsed time does not change the remaining wait: $P(X\\gt s+t\\mid X\\gt s)=P(X\\gt t)$. Only the exponential (continuous) and geometric (discrete) have it." },
  { term: "Confusion matrix", topic: "machine-learning", def: "A table of a classifier's true versus predicted labels — true/false positives and negatives — from which accuracy, precision, and recall are read off." },
  { term: "F1 score", topic: "machine-learning", def: "The harmonic mean of precision and recall, $2PR/(P+R)$ — one number balancing the two, especially useful on imbalanced data." },
  { term: "Convexity", topic: "calculus", def: "A function is convex if every chord lies on or above its graph (equivalently its second derivative is $\\ge 0$). Convex problems have a single global minimum, making optimization reliable." },
  { term: "Principal Component Analysis (PCA)", topic: "linear-algebra", def: "An unsupervised method that finds the orthogonal directions of greatest variance (the principal components — eigenvectors of the covariance matrix) and projects data onto the top few, reducing dimensions while keeping the most information." },
  { term: "Bagging", topic: "machine-learning", def: "Bootstrap aggregating: train many models on bootstrap resamples of the data and average their predictions. It cuts variance by decorrelating the models' errors — a random forest is bagging applied to decision trees." },
  { term: "Dimensionality reduction", topic: "machine-learning", def: "Mapping high-dimensional data to fewer dimensions while preserving structure — for visualization, denoising, or speed. Linear methods (PCA) keep variance directions; nonlinear ones (t-SNE, UMAP) preserve local neighborhoods." },
  { term: "Curse of dimensionality", topic: "machine-learning", def: "As the number of features grows, data becomes sparse and pairwise distances concentrate (points look almost equidistant), so methods that rely on locality — kNN, density estimation — degrade and need exponentially more data." },
  { term: "Feature scaling", topic: "machine-learning", def: "Putting features on a comparable scale — standardization (subtract the mean, divide by the standard deviation) or min-max normalization — so distance- and gradient-based methods (kNN, SVM, neural nets) are not dominated by large-range features." },
  { term: "Stochastic gradient descent (SGD)", topic: "deep-learning", def: "Gradient descent that updates parameters from a single example or a small mini-batch at a time instead of the whole dataset: far cheaper per step, and the gradient noise helps escape shallow minima. The workhorse optimizer of deep learning." },
  { term: "Likelihood", topic: "probability-statistics", def: "$p(D\\mid\\theta)$ read as a function of the parameter $\\theta$ for fixed data — how well each parameter value explains what was observed. It is not a probability distribution over $\\theta$." },
  { term: "Conjugate prior", topic: "probability-statistics", def: "A prior whose posterior stays in the same family (e.g. Beta + Binomial → Beta), so Bayesian updating is closed-form arithmetic on the parameters instead of an integral." },
  { term: "Maximum a posteriori (MAP)", topic: "probability-statistics", def: "The parameter value that maximizes the posterior — its mode. It equals the MLE under a flat prior; otherwise it is the MLE regularized by the prior." },
  { term: "Credible interval", topic: "probability-statistics", def: "An interval holding a stated posterior probability (e.g. 95%) of the parameter — a direct probability statement about $\\theta$, unlike a frequentist confidence interval." },
  { term: "Posterior predictive distribution", topic: "probability-statistics", def: "$p(x_{\\text{new}}\\mid D)=\\int p(x_{\\text{new}}\\mid\\theta)\\,p(\\theta\\mid D)\\,d\\theta$ — predicts new data by averaging the likelihood over the posterior, carrying parameter uncertainty." },
  { term: "Markov chain Monte Carlo (MCMC)", topic: "probability-statistics", def: "Algorithms that sample from a posterior by simulating a Markov chain whose stationary distribution is that posterior (e.g. Metropolis–Hastings); the samples drive Monte Carlo estimates." },
  { term: "Variational inference", topic: "probability-statistics", def: "Approximates an intractable posterior by fitting a simpler distribution $q$ to it via optimization — maximizing the ELBO. Fast and scalable, but approximate and usually over-confident." },
  { term: "Evidence lower bound (ELBO)", topic: "probability-statistics", def: "$\\mathcal L=\\log p(D)-\\mathrm{KL}\\!\\big(q\\,\\|\\,p(\\theta\\mid D)\\big)$; maximizing it (the objective of variational inference) minimizes the KL from $q$ to the true posterior." },
  { term: "Metropolis–Hastings", topic: "probability-statistics", def: "An MCMC method: propose a move and accept it with a probability set by the posterior ratio, which cancels the evidence $p(D)$ — so it needs the posterior only up to a constant (likelihood × prior)." },
  { term: "Marginal likelihood", topic: "probability-statistics", def: "The evidence $p(D)=\\int p(D\\mid\\theta)p(\\theta)\\,d\\theta$ — the posterior's normalizing constant, also used to compare models (Bayesian model selection)." },
  { term: "Confounder", topic: "probability-statistics", def: "A variable that causes both the treatment $X$ and the outcome $Y$, creating a non-causal association between them — the central obstacle to causal inference from observational data." },
  { term: "Collider", topic: "probability-statistics", def: "A common effect of two variables ($X\\to Z\\leftarrow Y$). Conditioning on a collider (or its descendant) opens a spurious association — the mechanism behind selection bias." },
  { term: "Backdoor criterion", topic: "probability-statistics", def: "A rule for choosing an adjustment set $Z$: block every non-causal path into $X$ and include no descendant of $X$. Then $P(Y\\mid\\text{do}(X))=\\sum_z P(Y\\mid X,z)P(z)$." },
  { term: "do-operator", topic: "probability-statistics", def: "$P(Y\\mid\\text{do}(X{=}x))$ denotes intervening to set $X=x$ (deleting arrows into $X$), versus merely observing $X=x$, which can carry confounding." },
  { term: "Propensity score", topic: "probability-statistics", def: "$e(Z)=P(X{=}1\\mid Z)$, the probability of treatment given covariates; matching or weighting on it balances all of $Z$ at once." },
  { term: "Instrumental variable", topic: "probability-statistics", def: "A variable that affects the treatment $X$ but has no direct effect on $Y$ and no shared confounder; it identifies causal effects when confounders are unmeasured (Wald estimator)." },
  { term: "d-separation", topic: "probability-statistics", def: "A graphical test for conditional independence: $X$ and $Y$ are independent given $Z$ when every path between them is blocked (a non-collider in $Z$, or a collider with no descendant in $Z$)." },
  { term: "Potential outcomes", topic: "probability-statistics", def: "$Y(1)$ and $Y(0)$: a unit's outcomes if treated versus untreated. Only one is observed (the fundamental problem of causal inference); the ATE is $\\mathbb E[Y(1)-Y(0)]$." },
  { term: "Average treatment effect (ATE)", topic: "probability-statistics", def: "$\\mathbb E[Y(1)-Y(0)]$, the mean causal effect of treatment across the population; estimable by a randomized experiment's difference in mean outcomes." },
  { term: "Difference-in-differences", topic: "probability-statistics", def: "An observational estimator equal to (treated group's change) minus (control group's change); valid under the parallel-trends assumption." },
  { term: "Causal DAG", topic: "probability-statistics", def: "A directed acyclic graph whose edges $X\\to Y$ assert direct causation; its path structure dictates which variables to adjust for to identify an effect." },
  { term: "Simpson's paradox", topic: "probability-statistics", def: "An association present within every subgroup can reverse in the aggregate when a confounder is unevenly distributed across the groups." },
  { term: "Lagrangian", topic: "calculus", def: "$L(x,\\lambda,\\nu)=f(x)+\\sum_i\\lambda_i g_i(x)+\\sum_j\\nu_j h_j(x)$ — folds constraints into the objective via multipliers ($\\lambda_i\\ge 0$ for inequalities). Its stationary points characterize constrained optima." },
  { term: "Dual function", topic: "calculus", def: "$g(\\lambda,\\nu)=\\inf_x L(x,\\lambda,\\nu)$ — the Lagrangian minimized over $x$. Always concave (an infimum of affine functions) and a lower bound on the primal optimum." },
  { term: "Weak duality", topic: "calculus", def: "$d^\\star\\le p^\\star$: the dual optimum never exceeds the primal optimum, for <em>any</em> problem. Their difference is the duality gap." },
  { term: "Strong duality", topic: "calculus", def: "$d^\\star=p^\\star$ (zero duality gap). Holds for convex problems under Slater's condition, so solving the dual solves the primal." },
  { term: "Duality gap", topic: "calculus", def: "$p^\\star-d^\\star\\ge 0$, the shortfall between the primal and dual optima. It is zero exactly when strong duality holds." },
  { term: "KKT conditions", topic: "calculus", def: "Karush–Kuhn–Tucker: stationarity ($\\nabla_x L=0$), primal and dual feasibility ($\\lambda\\ge 0$), and complementary slackness — necessary and sufficient for optimality in convex problems with strong duality." },
  { term: "Complementary slackness", topic: "calculus", def: "$\\lambda_i^\\star\\, g_i(x^\\star)=0$: each inequality constraint is either active ($g_i=0$) or has a zero multiplier. It identifies an SVM's support vectors." },
  { term: "Slater's condition", topic: "calculus", def: "A constraint qualification: a strictly feasible point exists (some $x$ with every $g_i(x)\\lt 0$). It guarantees strong duality for convex problems." },
  { term: "Shadow price", topic: "calculus", def: "The optimal multiplier $\\lambda_i^\\star$ read as sensitivity — how much the optimum would improve per unit relaxation of constraint $i$." },
  { term: "Convex set", topic: "calculus", def: "A set that contains the entire line segment between any two of its points. Convex optimization minimizes a convex function over a convex set, where every local optimum is global." },
  { term: "Proximal operator", topic: "calculus", def: "$\\mathrm{prox}_{\\lambda h}(y)=\\arg\\min_x\\big(h(x)+\\tfrac{1}{2\\lambda}\\lVert x-y\\rVert^2\\big)$ — takes a step toward minimizing $h$ while staying near $y$. Generalizes projection (the prox of a set's indicator is projection onto it)." },
  { term: "Soft-thresholding", topic: "calculus", def: "$S_\\lambda(x)=\\mathrm{sign}(x)\\max(|x|-\\lambda,0)$ — the proximal operator of the $\\ell_1$ penalty. Shrinks each coordinate toward $0$ by $\\lambda$ and zeroes anything smaller, producing lasso sparsity." },
  { term: "Subgradient", topic: "calculus", def: "A generalization of the derivative for convex functions: any slope of a line lying entirely below the function. At a kink there is an interval of them (for $|x|$ at $0$, all of $[-1,1]$)." },
  { term: "Projected gradient descent", topic: "calculus", def: "For minimizing $f$ over a feasible set $C$: take a gradient step, then project back onto $C$ — $x_{k+1}=\\Pi_C(x_k-\\eta\\nabla f(x_k))$. Handles constraints while keeping the cheap gradient step." },
  { term: "Proximal gradient descent (ISTA)", topic: "calculus", def: "For $f+h$ with $f$ smooth and $h$ non-smooth convex: alternate a gradient step on $f$ with a prox step on $h$. For lasso this is ISTA (soft-thresholding); FISTA adds momentum for an $O(1/k^2)$ rate." },
  { term: "Mixture of Experts (MoE)", topic: "llm", def: "An architecture that replaces a transformer's feed-forward network with $N$ parallel experts plus a router; each token uses only its top-$k$, so capacity scales with $N$ while per-token compute scales with $k$." },
  { term: "Top-k routing", topic: "llm", def: "The MoE gating mechanism: a small router scores the $N$ experts and dispatches each token to its $k$ highest-scoring ones, whose outputs are combined by a gate-weighted sum." },
  { term: "Conditional computation", topic: "llm", def: "Running only the input-relevant part of a network (e.g. the experts an MoE router selects) instead of the whole model on every input — capacity without proportional compute." },
  { term: "State-space model (SSM)", topic: "llm", def: "A sequence model (S4, Mamba) that carries a hidden state by a linear recurrence $h_t=A h_{t-1}+B x_t$ — $O(n)$ time and $O(1)$ inference memory, the leading linear-time alternative to attention. Mamba makes $A,B,C$ input-dependent." },
  { term: "Load balancing (MoE)", topic: "llm", def: "Techniques — an auxiliary loss plus expert-capacity caps — that stop an MoE router from collapsing onto a few experts, keeping token assignment spread across all of them." },
  { term: "Vision Transformer (ViT)", topic: "deep-learning", def: "Applies a transformer encoder to images by splitting them into fixed-size patches, embedding each as a token, and processing the sequence with self-attention — no convolutions, global context from the first layer." },
  { term: "Patch embedding", topic: "deep-learning", def: "The linear projection of each flattened image patch ($p\\times p\\times c$ pixels) to the model dimension, turning an image into a sequence of patch-tokens for a Vision Transformer." },
  { term: "CLIP", topic: "deep-learning", def: "A model with paired image (ViT) and text encoders trained contrastively so matching image-caption pairs align in a shared embedding space; enables zero-shot image classification." },
  { term: "Multimodal model", topic: "deep-learning", def: "A model that handles more than one modality (text, images, audio) in one architecture — usually by projecting each modality into a shared token space the transformer attends over." },
  { term: "[CLS] token", topic: "deep-learning", def: "A learnable token prepended to a transformer's input whose final hidden state serves as the aggregate sequence representation (used for classification in BERT and ViT)." },
  { term: "t-SNE", topic: "machine-learning", def: "A nonlinear dimensionality-reduction method for 2-D visualization that preserves local neighborhoods, revealing clusters. Caveat: its inter-cluster distances and cluster sizes are not meaningful." },
  { term: "UMAP", topic: "machine-learning", def: "A nonlinear visualization method like t-SNE but faster and preserving more global structure; embeds high-dimensional data into 2–3D to explore cluster structure." },
  { term: "Whitening", topic: "machine-learning", def: "A preprocessing step (often via PCA) that decorrelates features and rescales each to unit variance, leaving inputs uncorrelated and equally scaled." },
  { term: "Explained variance ratio", topic: "machine-learning", def: "A principal component's eigenvalue divided by the total of all eigenvalues — the fraction of the data's variance that component captures; used to choose how many components to keep." },
  { term: "Manifold", topic: "machine-learning", def: "A lower-dimensional surface that high-dimensional data lies near; dimensionality reduction recovers coordinates on it (the \"manifold hypothesis\")." },
  { term: "Graph Neural Network (GNN)", topic: "deep-learning", def: "A neural network for graph-structured data (nodes + edges): each layer updates a node's features by aggregating its neighbors' (message passing). Powers molecules, recommendation, and knowledge graphs." },
  { term: "Message passing", topic: "deep-learning", def: "The core GNN operation: each node updates its representation by aggregating (sum/mean/max) its neighbors' features and transforming the result; $k$ layers reach the $k$-hop neighborhood." },
  { term: "Over-smoothing", topic: "deep-learning", def: "The failure mode of deep GNNs: repeated message passing diffuses features until all nodes converge to the same vector, erasing distinctions — which is why GNNs stay shallow (2–4 layers)." },
  { term: "Graph attention (GAT)", topic: "deep-learning", def: "A GNN that learns per-neighbor attention weights instead of uniform averaging — self-attention restricted to the graph's edges, so more relevant neighbors count more." },
  { term: "Reparameterization trick", topic: "deep-learning", def: "Rewriting a random sample $z\\sim\\mathcal{N}(\\mu,\\sigma^2)$ as $z=\\mu+\\sigma\\,\\varepsilon$ with $\\varepsilon\\sim\\mathcal{N}(0,1)$ fixed, so the randomness sits outside the computation graph and gradients flow through $\\mu$ and $\\sigma$ — the key that lets a VAE train by backprop." },
  { term: "Latent variable", topic: "deep-learning", def: "A hidden, unobserved variable (often $z$) a model posits to explain the data — e.g. a VAE's compressed code or a document's topic. It is inferred/learned rather than directly measured." },
  { term: "Self-supervised learning (SSL)", topic: "deep-learning", def: "Learning representations from unlabelled data via a pretext task whose labels come free from the data (mask-and-predict, next-token, same-image?), then fine-tuning on a little labelled data. The engine behind foundation models." },
  { term: "Contrastive learning", topic: "deep-learning", def: "A self-supervised family: train an encoder so positive pairs (two views of the same item) land close in embedding space and negatives (everything else) land far apart — clustering by similarity with no labels." },
  { term: "InfoNCE", topic: "deep-learning", def: "The standard contrastive loss: a softmax cross-entropy over similarities (scaled by temperature $\\tau$) that makes the positive win against the negatives. Minimising it maximises a lower bound on the mutual information between the two views." },
  { term: "Pretext task", topic: "deep-learning", def: "A self-supervised puzzle whose answer is carved from the input itself (predict a masked word, reconstruct hidden patches). The point is the representation the model must build to solve it, not the puzzle." },
  { term: "Representation collapse", topic: "deep-learning", def: "The failure where an encoder maps every input to the same vector, trivially minimising a positives-only loss. Prevented by negatives, or by anti-collapse tricks (BYOL/DINO's momentum encoder plus stop-gradient)." },
  { term: "Double descent", topic: "deep-learning", def: "A modern phenomenon overturning the classic U-curve: as model capacity grows past the interpolation threshold, test error spikes then descends a second time, so a larger over-parameterized model can generalize better than the classical sweet spot." },
  { term: "Interpolation threshold", topic: "deep-learning", def: "The model capacity at which a network first fits the training data exactly (zero training error). The classical overfitting peak sits here; beyond it lies the over-parameterized regime and double descent's second descent." },
  { term: "Grokking", topic: "deep-learning", def: "Delayed generalization: a network reaches near-100% training accuracy almost immediately but only generalizes (validation accuracy jumps) thousands of steps later, typically under weight decay — evidence that which solution the optimizer settles into matters as much as fitting the data." },
  { term: "Implicit regularization", topic: "deep-learning", def: "The optimizer's built-in bias (from SGD, architecture, initialization, and weight decay) toward simpler, smoother, lower-norm solutions among the many that fit the data — a key reason over-parameterized models generalize (it underlies double descent and grokking)." },
  { term: "Lottery ticket hypothesis", topic: "deep-learning", def: "The claim that a randomly-initialized dense network already contains a small sparse subnetwork (a \"winning ticket\") which, trained alone from the <em>same</em> initial weights, matches the full network's accuracy — found by training, pruning small-magnitude weights, then rewinding the rest to their init." },
  { term: "Pruning", topic: "deep-learning", def: "Removing weights (or whole neurons/channels) from a trained network — usually the smallest-magnitude ones — to shrink it for cheaper, faster inference with little accuracy loss. The lottery ticket hypothesis is its theoretical underpinning." },
  { term: "Weight decay", topic: "deep-learning", def: "An $L_2$ regularizer that shrinks weights toward zero each step (adding $\\lambda\\|w\\|^2$ to the loss). It biases training toward smaller, smoother solutions and is central to phenomena like grokking." },
  { term: "AI agent", topic: "llm", def: "An LLM that runs a loop — Thought → Action (call a tool) → Observation — feeding each result back into its reasoning until it can answer, rather than responding in one shot. The basis of coding assistants, research agents, and computer-use systems." },
  { term: "ReAct", topic: "llm", def: "An agent pattern (Reason + Act): the model interleaves reasoning steps with tool-using actions and their observations, choosing each next action from what it has seen so far — the canonical reason-act-observe loop." },
  { term: "Tool use (function calling)", topic: "llm", def: "Letting an LLM invoke external functions or APIs (search, calculator, code execution) by emitting a structured call, then continuing with the returned result — extending it beyond its frozen parametric knowledge." },
  { term: "Stationarity (time series)", topic: "time-series", def: "A time series whose statistical properties — mean, variance, and autocovariance — don't change over time. Most classical methods (ARMA/ARIMA) require it; differencing and log transforms move a series toward it." },
  { term: "Autocorrelation (ACF)", topic: "time-series", def: "The correlation of a series with a time-shifted copy of itself at lag $k$. The ACF plot is a time series' fingerprint — slow decay signals a trend, periodic spikes signal seasonality." },
  { term: "ARIMA", topic: "time-series", def: "AutoRegressive Integrated Moving-Average, ARIMA(p, d, q): regress on the last $p$ values (AR) and the last $q$ forecast errors (MA) after differencing $d$ times (I) to reach stationarity. The classical forecasting workhorse." },
  { term: "Exponential smoothing", topic: "time-series", def: "Forecasting by a weighted average of past values with geometrically decaying weights ($\\hat{y}_{t+1}=\\alpha y_t+(1-\\alpha)\\hat{y}_t$). Holt adds a trend, Holt–Winters adds seasonality (the ETS family)." },
  { term: "Backtesting", topic: "time-series", def: "Evaluating a forecaster on held-out future data via rolling-origin (time-series cross-) validation — forecasting from many successive cut-points so each test point lies in the future of its training data." },
  { term: "Seasonality", topic: "time-series", def: "A pattern in a time series that repeats over a fixed period (daily, weekly, yearly). Distinct from a cycle, which swings with no fixed period." },
  { term: "Score-function estimator (REINFORCE)", topic: "reinforcement-learning", def: "A way to differentiate an expectation $\\mathbb{E}_{x\\sim p_\\theta}[f(x)]$ as $\\mathbb{E}[f(x)\\,\\nabla_\\theta\\log p_\\theta(x)]$. It treats $f$ as a black box, so it works for non-differentiable or discrete outcomes (RL policy gradients) — at the cost of high variance (hence baselines)." },
  { term: "Pathwise gradient (reparameterization)", topic: "deep-learning", def: "The low-variance alternative to the score-function estimator: write the sample as $x=g(\\theta,\\varepsilon)$ with fixed noise $\\varepsilon$ and push the gradient straight through $f$ and $g$. Needs a differentiable $f$ and a continuous, reparameterizable distribution (used in VAEs)." },
  { term: "Mechanistic interpretability", topic: "llm", def: "Reverse-engineering a neural network's internal computations into human-understandable algorithms (circuits and features) — the effort to turn a black box into something auditable and steerable." },
  { term: "Superposition", topic: "llm", def: "A network representing more features than it has dimensions by storing them as many near-orthogonal directions in activation space. It is why single neurons are polysemantic (firing for many unrelated concepts)." },
  { term: "Sparse autoencoder (SAE)", topic: "llm", def: "An overcomplete autoencoder with a sparsity penalty, trained on a model's activations to decompose them into many monosemantic features — dictionary learning that disentangles superposition into interpretable pieces." },
  { term: "Polysemantic / monosemantic", topic: "llm", def: "Polysemantic: one unit fires for many unrelated concepts (the norm, caused by superposition). Monosemantic: a unit that responds to a single interpretable concept — what sparse autoencoders aim to recover." },
  { term: "Induction head", topic: "llm", def: "An attention head (usually a pair working together) that implements in-context copying: it finds an earlier occurrence of the current token and predicts whatever followed it last time. A core mechanism behind in-context learning." },
  { term: "Circuit (interpretability)", topic: "llm", def: "A small, human-understandable subgraph of a network's computation that performs a specific function (e.g. induction heads, or an indirect-object-identification circuit) — the unit of analysis in mechanistic interpretability." },
  { term: "Fourier transform", topic: "deep-learning", def: "A reversible decomposition of a signal into the sine waves (frequencies) that compose it. The frequency-domain view turns convolution into multiplication and underlies signal processing, spectral methods, and sinusoidal positional encodings." },
  { term: "Convolution theorem", topic: "deep-learning", def: "Convolution in one domain equals pointwise multiplication in the other: $\\mathcal{F}\\{f*g\\}=\\mathcal{F}\\{f\\}\\cdot\\mathcal{F}\\{g\\}$. It lets an FFT compute convolution in $O(n\\log n)$, and reveals that a convolution kernel is really a frequency filter." },
  { term: "PAC learning", topic: "deep-learning", def: "Probably Approximately Correct: a hypothesis class is PAC-learnable if a finite sample makes the learned hypothesis's error $\\le\\epsilon$ with probability $\\ge 1-\\delta$. The formal account of when learning from finite data is guaranteed to work." },
  { term: "VC dimension", topic: "deep-learning", def: "The capacity of a hypothesis class — the largest number of points it can shatter. It controls sample complexity in PAC learning: higher VC dimension needs more data to generalize (a 2-D linear classifier has VC dimension 3)." },
  { term: "Shattering", topic: "deep-learning", def: "A hypothesis class shatters a set of points if it can realize every possible $+/-$ labeling of them. The size of the largest set it can shatter is its VC dimension." },
  { term: "Nash equilibrium", topic: "game-theory", def: "A strategy profile where no player can improve their payoff by unilaterally changing only their own move — a \"no regrets\" state. Every finite game has at least one (allowing mixed strategies)." },
  { term: "Dominant strategy", topic: "game-theory", def: "A choice that is best no matter what the other players do; a rational player always plays it. Its opposite, a dominated strategy (never the best response), is never rationally played." },
  { term: "Zero-sum game", topic: "game-theory", def: "A game in which one player's gain is exactly the other's loss. Von Neumann's minimax theorem gives such games a well-defined value; a GAN is trained as a zero-sum game." },
  { term: "Prisoner's Dilemma", topic: "game-theory", def: "The canonical game where mutual defection is the unique Nash equilibrium, yet both players would be better off cooperating — individual rationality producing a collectively worse outcome." },
  { term: "Mixed strategy", topic: "game-theory", def: "A probability distribution over your choices (e.g. rock/paper/scissors each with probability one-third). Needed when no pure equilibrium exists; Nash's theorem guarantees a mixed one always does." },
  { term: "Pareto optimality", topic: "game-theory", def: "An outcome where no one can be made better off without making someone worse off. Distinct from Nash equilibrium (merely stable): the Prisoner's Dilemma's equilibrium is not Pareto-optimal." },
  { term: "Minimax theorem", topic: "game-theory", def: "Von Neumann's result that every finite two-player zero-sum game has a value: $\\max\\min = \\min\\max$. The most you can guarantee equals the least the opponent can hold you to — the basis of GANs, self-play, and game-tree search." },
  { term: "Best response", topic: "game-theory", def: "The strategy that maximizes your payoff given the other players' fixed choices. A Nash equilibrium is precisely a profile where every player is simultaneously playing a best response." },
  { term: "Tit-for-tat", topic: "game-theory", def: "An iterated-Prisoner's-Dilemma strategy: cooperate on the first move, then copy the opponent's last move. Winner of Axelrod's tournaments — nice, retaliatory, forgiving, and clear." },
  { term: "Grim trigger", topic: "game-theory", def: "A repeated-game strategy: cooperate until the opponent defects once, then defect forever. The harshest credible punishment; it makes cooperation a Nash equilibrium but is unforgiving of mistakes." },
  { term: "Folk theorem", topic: "game-theory", def: "In an infinitely repeated game with patient players, any payoff profile above each player's one-shot minimax can be sustained as a Nash equilibrium — so repetition creates a multitude of equilibria, not a unique one." },
  { term: "Normalizing flow", topic: "deep-learning", def: "A generative model that maps a simple base distribution through an <em>invertible</em> network, giving the <em>exact</em> likelihood via the change-of-variables formula. Unlike a VAE (a bound) or GAN (implicit), it can score any point's probability exactly — at the cost of architectures constrained to be invertible (RealNVP, Glow)." },
  { term: "Change of variables (density)", topic: "deep-learning", def: "How a probability density transforms under an invertible map $x=f(z)$: $p_X(x)=p_Z(f^{-1}(x))\\,\\left|\\det\\frac{\\partial f^{-1}}{\\partial x}\\right|$. The Jacobian-determinant factor corrects for how $f$ stretches or shrinks volume — the engine behind normalizing flows." },
  { term: "Knowledge distillation", topic: "deep-learning", def: "Training a small \"student\" model to match a large \"teacher's\" soft output probabilities rather than just the hard labels. The soft targets carry similarity structure (dark knowledge), so the student generalizes like the teacher at a fraction of the size — e.g. DistilBERT." },
  { term: "Dark knowledge", topic: "deep-learning", def: "The information in a model's soft output beyond the top class — the relative probabilities of the <em>wrong</em> classes (a \"7\" is a bit like a \"1\", not at all like a \"cat\"). Knowledge distillation transfers it to a student via soft targets." },
  { term: "Compute-optimal scaling (Chinchilla)", topic: "llm", def: "For a fixed training-compute budget, the parameter/data split that minimizes loss. The Chinchilla result showed earlier LLMs were oversized and <em>undertrained</em> — you should scale parameters and tokens together (roughly 20 tokens per parameter)." },
  { term: "Power law", topic: "llm", def: "A relationship of the form $y = a\\,x^{-\\alpha}$ — a straight line on log-log axes. Neural scaling laws are power laws (loss falls as a power of model size, data, and compute), as are Zipf's law and many natural phenomena." },
  { term: "Markov's inequality", topic: "probability-statistics", def: "For a non-negative random variable, $P(X \\ge a) \\le \\mathbb{E}[X]/a$. The most basic tail bound — it uses only the mean — and the seed from which Chebyshev's and Hoeffding's inequalities are derived." },
  { term: "Chebyshev's inequality", topic: "probability-statistics", def: "$P(|X-\\mu| \\ge k\\sigma) \\le 1/k^2$ — a tail bound using the variance. Applied to a sample mean (variance $\\sigma^2/n$), it proves the weak law of large numbers." },
  { term: "Hoeffding's inequality", topic: "probability-statistics", def: "For bounded i.i.d. variables, $P(|\\bar X-\\mu| \\ge \\epsilon) \\le 2e^{-2n\\epsilon^2/(b-a)^2}$ — an <em>exponential</em> concentration bound, far tighter than Chebyshev's. It is the source of the $\\log(1/\\delta)$ in PAC sample complexity and the confidence bonus in UCB." },
  { term: "Data processing inequality", topic: "information-theory", def: "For a Markov chain $X\\to Y\\to Z$, $I(X;Z) \\le I(X;Y)$: processing can only lose information about $X$, never create it. The backbone of the information bottleneck — feature engineering repackages information, it cannot add it." },
  { term: "Sufficient statistic", topic: "information-theory", def: "A function $T(X)$ of the data that retains <em>all</em> the information the data carries about a parameter or target — conditioning on it makes the rest of the data irrelevant. It achieves equality in the data processing inequality (loses nothing)." },
  { term: "Evolutionarily stable strategy (ESS)", topic: "game-theory", def: "A strategy that, once common in a population, cannot be invaded by any rare mutant — if (almost) everyone plays it, no alternative does better. A refinement of Nash equilibrium with an added stability condition; the stable outcome of evolutionary game dynamics." },
  { term: "Replicator dynamics", topic: "game-theory", def: "The core equation of evolutionary game theory: a strategy's population share grows when its fitness beats the population average, $\\dot{x}_i = x_i\\,(f_i - \\bar f)$. Its stable fixed points are the evolutionarily stable strategies." },
  { term: "Hawk–Dove game", topic: "game-theory", def: "A classic evolutionary game: hawks fight over a resource, doves share. Neither pure strategy is stable, so the ESS is a <em>mixed</em> population — a mixed equilibrium reached by selection rather than reasoning." },
  { term: "Prediction interval", topic: "time-series", def: "A range a <em>future observation</em> is expected to fall within with some probability (e.g. 95%). Wider than a confidence interval because it includes the data's own randomness, not just parameter uncertainty; in forecasting it fans out with the horizon." },
  { term: "Forecast horizon", topic: "time-series", def: "How many steps ahead a forecast reaches. Forecast uncertainty grows with the horizon — bounded for a mean-reverting process, but unbounded ($\\propto \\sqrt h$) for a random walk." },
  { term: "Random walk", topic: "time-series", def: "A process where each value is the previous one plus independent noise, $x_t = x_{t-1} + \\epsilon_t$. Non-stationary, with forecast variance growing linearly in the horizon — the boundary case ($\\phi = 1$) of an AR(1)." },
  { term: "Mechanism design", topic: "game-theory", def: "Game theory in reverse: instead of analyzing a fixed game, you <em>design</em> the rules so that self-interested players, each pursuing their best strategy, are led to a desired outcome. The foundation of auction and market design." },
  { term: "Vickrey auction (second-price)", topic: "game-theory", def: "A sealed-bid auction where the highest bidder wins but pays the <em>second</em>-highest bid. Bidding your true value is a dominant strategy, so it elicits honest valuations — the basis of VCG and the ad auctions behind Google and Meta." },
  { term: "Incentive compatibility", topic: "game-theory", def: "A mechanism is incentive-compatible (truthful, or strategyproof) when honest reporting is each player's best strategy, so no one gains by lying. The Vickrey auction is the canonical example." },
  { term: "Internal covariate shift", topic: "deep-learning", def: "The drift in the distribution of a layer's inputs as the layers beneath it update during training, forcing every layer to chase a moving target. Reducing it was the original motivation for batch normalization." },
  { term: "Early stopping", topic: "deep-learning", def: "A regularizer: halt training once validation error stops improving, before the model overfits the training set. Free and effective — it caps effective model complexity by capping training time." },
  { term: "Data augmentation", topic: "deep-learning", def: "Expanding a training set with label-preserving transformations of existing examples (crops, flips, rotations, added noise). It teaches the model invariances and fights overfitting without collecting new data." },
  { term: "Shapley value", topic: "game-theory", def: "In a cooperative game, a player's fair share of the joint payoff: their average marginal contribution $v(S\\cup\\{i\\})-v(S)$ across all orders of forming the coalition. The unique split satisfying efficiency, symmetry, null-player, and additivity." },
  { term: "Cooperative game", topic: "game-theory", def: "A game in which players form coalitions and share a collective payoff, shifting the question from \"what will each player do?\" to \"how should the gains be divided fairly?\" — answered by the Shapley value." },
  { term: "SHAP", topic: "machine-learning", def: "SHapley Additive exPlanations: a model-explanation method that gives each feature its Shapley value — treating a prediction as a cooperative game's payoff and the features as players — to attribute the prediction fairly across inputs." },
  { term: "Bayesian game", topic: "game-theory", def: "A game of <em>incomplete information</em>: players don't know one another's payoffs. Each player's private information is modeled as a \"type\" drawn from a commonly-known prior, so you optimize against a distribution of possible opponents rather than a single known one." },
  { term: "Bayesian Nash equilibrium", topic: "game-theory", def: "The solution concept for Bayesian games: a strategy for <em>every type</em> of every player such that each type best-responds given its beliefs about the other players' types." },
  { term: "Signaling", topic: "game-theory", def: "When an informed player takes a costly, type-dependent action that credibly reveals private information — education signals ability, a warranty signals quality. Cheap talk is ignored; costly signals are believed because they would not pay off for the wrong type." },
  { term: "Sampling distribution", topic: "probability-statistics", def: "The distribution of a statistic (such as the sample mean) across all possible samples of a given size. Its spread is the standard error; the Central Limit Theorem says it is approximately normal for large $n$. The bootstrap approximates it by resampling." },
  { term: "Resampling", topic: "probability-statistics", def: "Drawing new pseudo-samples from your own data — usually <em>with replacement</em> — to estimate how much a statistic would vary. The engine of the bootstrap, requiring no formula and no distributional assumption." },
  { term: "Percentile", topic: "probability-statistics", def: "The value below which a given fraction of the data falls (the 95th percentile exceeds 95% of values). The middle 95% — the 2.5th to 97.5th percentile — of a bootstrap distribution gives a confidence interval." },
  { term: "Gaussian process", topic: "machine-learning", def: "A prior over <em>functions</em>: a non-parametric model where any finite set of points is jointly Gaussian. A kernel sets smoothness; conditioning on data gives a posterior mean (the prediction) plus a variance (calibrated error bars). Bayesian linear regression with infinitely many features." },
  { term: "Bayesian optimization", topic: "machine-learning", def: "Optimizing an expensive black-box function (e.g. tuning hyperparameters) by fitting a cheap surrogate — usually a Gaussian process — and evaluating where it predicts high value or high uncertainty. Explore-exploit on the posterior." },
  { term: "Acquisition function", topic: "machine-learning", def: "In Bayesian optimization, the rule that picks the next point to try by trading off the surrogate's predicted mean (exploit) against its variance (explore) — e.g. expected improvement or an upper confidence bound." },
  { term: "Power iteration", topic: "linear-algebra", def: "An iterative method that finds a matrix's <em>dominant</em> eigenvector by repeatedly multiplying by the matrix and renormalizing. It converges at a rate set by the ratio of the top two eigenvalues, and is the engine behind PageRank." },
  { term: "PageRank", topic: "algorithms", def: "Google's original page-ranking algorithm: model the web as a Markov chain of random surfing and find its stationary distribution — the dominant eigenvector of the link matrix — by power iteration. A page is important if important pages link to it." },
  { term: "Spectral radius", topic: "linear-algebra", def: "The largest absolute eigenvalue of a matrix. It decides whether repeated multiplication grows or decays (powers of $A$ vanish exactly when the spectral radius is below 1) and sets the convergence rate of power iteration." },
  { term: "Memory-bound (vs compute-bound)", topic: "llm", def: "A computation limited by data movement (memory bandwidth) rather than by arithmetic. LLM decode is memory-bound — each token reads <em>all</em> the weights — so throughput is roughly bandwidth ÷ bytes, and quantization (fewer bytes per weight) speeds it up." },
  { term: "Arithmetic intensity", topic: "llm", def: "The ratio of arithmetic operations to bytes moved from memory. Low intensity means memory-bound (limited by bandwidth); high intensity means compute-bound (limited by FLOPs). Batching and the KV cache raise it." },
  { term: "Speculative decoding", topic: "llm", def: "A decoding speedup: a small, fast \"draft\" model proposes several tokens, then the large model verifies them all in one parallel pass — turning many memory-bound steps into one and keeping the draft tokens that match." },
  { term: "Adversarial example", topic: "deep-learning", def: "An input carrying a tiny, often imperceptible perturbation crafted to make a model misclassify it with high confidence (the panda-to-gibbon flip). Such examples reveal that a low test error does not imply robustness." },
  { term: "Fast Gradient Sign Method (FGSM)", topic: "deep-learning", def: "A one-step adversarial attack: perturb each input feature by $\\epsilon$ in the sign direction of the loss gradient, $x' = x + \\epsilon\\,\\mathrm{sign}(\\nabla_x J)$. The gradient is taken with respect to the <em>input</em>, not the weights." },
  { term: "Adversarial training", topic: "deep-learning", def: "The standard defense against adversarial examples: generate attacks during training and feed them back as labeled examples, teaching the model to resist small malicious perturbations." },
  { term: "Fisher information", topic: "probability-statistics", def: "How much a sample tells you about a parameter: the expected curvature of the log-likelihood around the true value, $I(\\theta) = -\\mathbb{E}[\\partial^2_\\theta \\log L]$. A sharper peak means more information; it is additive over independent samples." },
  { term: "Cramér–Rao bound", topic: "probability-statistics", def: "A hard lower bound on the variance of <em>any</em> unbiased estimator: $\\mathrm{Var}(\\hat\\theta) \\ge 1/I(\\theta)$. No unbiased estimator can be more precise than the Fisher information allows." },
  { term: "Efficient estimator", topic: "probability-statistics", def: "An unbiased estimator whose variance attains the Cramér–Rao bound — the most precise possible. The maximum-likelihood estimator is asymptotically efficient (reaches the bound as the sample grows)." },
  { term: "Hidden Markov Model (HMM)", topic: "machine-learning", def: "A generative model for sequences: a Markov chain of <em>hidden</em> states, each emitting an observation you can see. Solved by the forward algorithm (likelihood), Viterbi (most likely state path), and Baum–Welch (learning the probabilities)." },
  { term: "Viterbi algorithm", topic: "machine-learning", def: "Dynamic programming that finds the single most likely hidden-state sequence of an HMM given the observations — the same recurrence as the forward algorithm, but with max in place of sum." },
  { term: "Baum–Welch algorithm", topic: "machine-learning", def: "The EM algorithm for HMMs: it iteratively estimates the transition and emission probabilities from observation sequences alone, without ever seeing the hidden states." },
  { term: "Gumbel-softmax (concrete distribution)", topic: "deep-learning", def: "A differentiable relaxation of sampling from a categorical: add Gumbel noise to the log-probabilities and apply a temperature-$\\tau$ softmax. As $\\tau \\to 0$ it approaches a one-hot sample; large $\\tau$ smooths toward uniform — so gradients can flow through a discrete choice." },
  { term: "Straight-through estimator", topic: "deep-learning", def: "A trick for backpropagating through a non-differentiable step (a hard threshold, $\\arg\\max$, or quantizer): use the discrete value on the forward pass, but treat the operation as the identity (or a soft surrogate) on the backward pass, so a usable gradient still flows." },
  { term: "Correlated equilibrium", topic: "game-theory", def: "A generalization of Nash equilibrium: a trusted device privately recommends a move to each player, and no one gains by deviating from their recommendation. Every Nash equilibrium is one (use independent signals), the set is computable by linear programming, and no-regret learning converges to it." },
  { term: "No-regret learning", topic: "game-theory", def: "An online learning rule whose average payoff approaches that of the best single fixed action in hindsight — its average \"regret\" goes to zero. When every player in a repeated game learns this way, their long-run average play converges to the set of correlated equilibria." },
  { term: "GARCH", topic: "time-series", def: "A time-series model for <em>time-varying</em> variance: today's variance depends on recent squared shocks and recent variances — GARCH(1,1) is $\\sigma_t^2 = \\omega + \\alpha\\,\\varepsilon_{t-1}^2 + \\beta\\,\\sigma_{t-1}^2$. It captures volatility clustering and is the variance counterpart to ARIMA's mean model." },
  { term: "Volatility clustering", topic: "time-series", def: "The empirical tendency of large changes to be followed by large changes, and calm by calm, so variance arrives in waves rather than staying constant. The key stylized fact of financial returns that GARCH models exist to capture." },
  { term: "Stackelberg game", topic: "game-theory", def: "A sequential game where a leader commits to an action first and a follower observes it and best-responds. Solved by backward induction; committing first — if the commitment is credible — can beat the simultaneous Nash outcome, a first-mover advantage." },
  { term: "Bilevel optimization", topic: "machine-learning", def: "An optimization nested inside another: an outer (leader) problem is optimized subject to the solution of an inner (follower) problem. Stackelberg games, hyperparameter tuning, and parts of meta-learning all have this leader-follower structure." },
  { term: "Meta-learning", topic: "deep-learning", def: "\"Learning to learn\": training across many tasks so a model can adapt to a <em>new</em> task from few examples. Rather than fitting one solution, it learns a starting point or strategy that adapts fast — the optimization-based cousin of transfer learning." },
  { term: "MAML (Model-Agnostic Meta-Learning)", topic: "deep-learning", def: "A meta-learning method that learns an <em>initialization</em> from which a few gradient steps solve a new task. It is bilevel: an inner loop adapts the parameters per task, and an outer loop optimizes the post-adaptation loss, differentiating through the inner step." },
  { term: "Few-shot learning", topic: "deep-learning", def: "Learning a new task from only a handful of labeled examples by leaning on knowledge transferred from prior tasks or pretraining. Meta-learning and a language model&#39;s in-context learning are two routes to it." },
  { term: "Classifier-free guidance", topic: "deep-learning", def: "A way to control how strongly a conditional diffusion model follows its prompt. Train one network both with and without the condition, then at sampling extrapolate $\\tilde{\\varepsilon} = \\varepsilon_{\\text{uncond}} + w(\\varepsilon_{\\text{cond}} - \\varepsilon_{\\text{uncond}})$. The guidance scale $w$ trades prompt fidelity for diversity — the \"CFG scale\" in Stable Diffusion and similar models." },
  { term: "Score matching", topic: "deep-learning", def: "Learning the <em>score function</em> $\\nabla_x \\log p(x)$ — the gradient of the log-density — instead of the density itself, which sidesteps the intractable normalizing constant. Score-based and diffusion generative models are trained this way." },
  { term: "Kolmogorov complexity", topic: "information-theory", def: "The information content of a <em>single</em> object $x$: the length of the shortest program (on a fixed universal computer) that outputs $x$ and halts. Random means incompressible ($K(x)$ near its own length); it is uncomputable, and averaged over a source it approaches the Shannon entropy." },
  { term: "Minimum description length (MDL)", topic: "machine-learning", def: "A model-selection principle: prefer the model that encodes the data <em>plus the model itself</em> in the fewest total bits. A practical, computable stand-in for Kolmogorov complexity and a precise form of Occam&#39;s razor." },
  { term: "Reservoir sampling", topic: "algorithms", def: "A one-pass algorithm that keeps a uniform random sample of k items from a stream of unknown length using O(k) memory: keep the first k, then for the i-th item replace a random held item with probability k/i. Every item ends up included with probability k/n." },
  { term: "Streaming algorithm", topic: "algorithms", def: "An algorithm that processes its input in one (or a few) passes using memory far smaller than the input — often sublinear or even O(1). Used when data is too large to store: reservoir sampling, count-min sketch, HyperLogLog." },
  { term: "Las Vegas algorithm", topic: "algorithms", def: "A randomized algorithm that is <em>always</em> correct but whose running time is random (e.g. randomized quicksort). Contrast with a Monte Carlo algorithm, which runs in fixed time but may be wrong with small probability." },
  { term: "Neural tangent kernel (NTK)", topic: "deep-learning", def: "In the infinite-width limit, gradient-descent training of a neural net behaves like kernel regression with a fixed kernel $K(x,x')=\\nabla_\\theta f(x)\\cdot\\nabla_\\theta f(x')$ frozen at initialization (\"lazy training\"). It explains why over-parameterized nets converge and generalize — though real finite nets do feature learning and beat their NTK." },
  { term: "Feature learning", topic: "deep-learning", def: "When a network reshapes its internal representations during training, rather than keeping them fixed (as in lazy / NTK training). Feature learning is widely believed to be why deep nets outperform fixed-kernel methods." },
  { term: "Total variation distance", topic: "information-theory", def: "The simplest distance between distributions: $\\mathrm{TV}(p,q)=\\tfrac12\\sum_x|p(x)-q(x)|$ — the largest gap in probability they assign to any single event. A true metric ranging over $[0,1]$, never asymmetric and never infinite." },
  { term: "Pinsker's inequality", topic: "information-theory", def: "Bounds total variation by KL divergence: $\\mathrm{TV}(p,q)\\le\\sqrt{\\tfrac12\\mathrm{KL}(p\\,\\|\\,q)}$. A small KL forces a small total variation, so minimizing cross-entropy makes distributions genuinely indistinguishable to any test." },
  { term: "Wasserstein distance", topic: "information-theory", def: "The \"earth-mover\" distance: the minimum cost to transport one distribution's mass to match another's. Geometry-aware and finite even for disjoint supports, which is why it yields useful gradients (WGAN) where KL blows up." },
  { term: "Jensen-Shannon divergence", topic: "information-theory", def: "A symmetric, bounded smoothing of KL: $\\mathrm{JS}(p,q)=\\tfrac12\\mathrm{KL}(p\\,\\|\\,m)+\\tfrac12\\mathrm{KL}(q\\,\\|\\,m)$ with $m=(p+q)/2$. Always finite, and its square root is a metric; the original GAN objective minimizes it." },
  { term: "Behavioral cloning", topic: "reinforcement-learning", def: "Imitation learning as plain supervised learning: train a policy to copy expert (state → action) pairs. Simple, but brittle — errors compound over the horizon as the agent drifts into states the expert never visited." },
  { term: "Imitation learning", topic: "reinforcement-learning", def: "Learning a policy from expert demonstrations instead of from a reward signal. Its main forms are behavioral cloning, DAgger, and inverse reinforcement learning." },
  { term: "Inverse reinforcement learning (IRL)", topic: "reinforcement-learning", def: "Recover the reward function an expert appears to optimize from their demonstrations, then plan with it. Often generalizes better than directly cloning actions, since the \"why\" transfers to new states." },
  { term: "DAgger", topic: "reinforcement-learning", def: "Dataset Aggregation: an iterative imitation method that fixes behavioral cloning's drift by querying the expert on the states the <em>learner</em> actually visits, then retraining on the growing aggregated dataset." },
  { term: "Reward shaping", topic: "reinforcement-learning", def: "Adding extra reward terms to steer learning toward a goal. Powerful but risky — poorly designed shaping invites reward hacking, where the agent maximizes the proxy instead of the intent." },
  { term: "Credit assignment", topic: "reinforcement-learning", def: "The problem of deciding which earlier actions deserve credit (or blame) for a much later reward — the core difficulty that discounting, TD learning, and advantage estimates exist to address." },
  { term: "Conformal prediction", topic: "machine-learning", def: "A distribution-free method that turns any model's outputs into <em>prediction sets</em> with a finite-sample guarantee: the set contains the true label with probability at least $1-\\alpha$, for any model and any data distribution (assuming exchangeability)." },
  { term: "Exchangeability", topic: "machine-learning", def: "A weaker assumption than i.i.d.: the joint distribution of a sequence is unchanged by reordering its elements. It is the minimal condition under which conformal prediction's coverage guarantee holds." },
  { term: "Calibration", topic: "machine-learning", def: "A model is calibrated when its stated confidence matches its real accuracy — among predictions made with 70% confidence, about 70% are correct. Calibration is approximate; conformal prediction makes coverage exact." },
  { term: "Coverage", topic: "machine-learning", def: "The probability that a prediction set or interval actually contains the true value. Conformal prediction guarantees coverage of at least $1-\\alpha$ regardless of how good or bad the underlying model is." },
  { term: "Doubly robust estimation", topic: "probability-statistics", def: "A causal-effect estimator (AIPW) that combines outcome regression with inverse-propensity weighting. It stays consistent if <em>either</em> the outcome model or the propensity model is correct — \"two chances to be right\"." },
  { term: "Inverse propensity weighting (IPW)", topic: "probability-statistics", def: "Estimating a causal effect by reweighting each observed outcome by one over the probability of the treatment it received given covariates, so the weighted sample mimics a randomized experiment. Unbiased only if the propensity model is correct." },
  { term: "Double machine learning (DML)", topic: "probability-statistics", def: "Plugging flexible ML models in for the nuisance functions (outcome and propensity) of a doubly-robust, orthogonalized estimator, fit with cross-fitting — yielding valid confidence intervals for a causal effect despite the bias ML models introduce." },
  { term: "Granger causality", topic: "time-series", def: "X Granger-causes Y if X's past values improve the forecast of Y beyond Y's own past. It is <em>predictive</em>, not interventional — it signals lead-lag information, not that intervening on X would change Y." },
  { term: "Vector autoregression (VAR)", topic: "time-series", def: "A multivariate time-series model in which each variable is regressed on the recent lags of itself <em>and</em> of all the others. The standard framework for forecasting interacting series and for testing Granger causality." },
  { term: "Cointegration", topic: "time-series", def: "Two or more non-stationary series that share a long-run equilibrium: each wanders like a random walk, yet some linear combination of them is stationary. The basis of error-correction models and pairs-trading strategies." },
  { term: "Brownian motion (Wiener process)", topic: "probability-statistics", def: "The continuous-time limit of a random walk: a nowhere-differentiable path with independent Gaussian increments $W_t - W_s \\sim \\mathcal{N}(0,\\,t-s)$. The canonical noise of stochastic differential equations, driving diffusion models, finance, and physics." },
  { term: "Stochastic process", topic: "probability-statistics", def: "A collection of random variables indexed by time (or space) — a model of randomness that evolves. Examples include random walks, the Poisson process, Brownian motion, and Markov chains." },
  { term: "Stochastic differential equation (SDE)", topic: "probability-statistics", def: "A differential equation driven by random noise, $\\mathrm{d}X = \\mu\\,\\mathrm{d}t + \\sigma\\,\\mathrm{d}W$, where $\\mathrm{d}W$ is a Brownian increment. The drift $\\mu$ sets the trend and the diffusion $\\sigma$ the randomness — the basis of diffusion models and quantitative finance." },
  { term: "Moment generating function (MGF)", topic: "probability-statistics", def: "$M(t)=\\mathbb{E}[e^{tX}]$: a transform whose derivatives at 0 give the moments of $X$, and which (when it exists) uniquely determines the distribution — handy for proving the CLT and for summing independent variables." },
  { term: "Core (cooperative game theory)", topic: "game-theory", def: "The set of payoff allocations that no coalition can improve on by breaking away: for every coalition $S$, its members' shares sum to at least $v(S)$. The stability concept of cooperative games — but it can be empty, and the Shapley value need not lie in it." },
  { term: "Coalition", topic: "game-theory", def: "A subset of players who cooperate and pool their payoff in a cooperative game. The value $v(S)$ a coalition $S$ can secure on its own is the raw material for both the Shapley value and the core." },
  { term: "Fictitious play", topic: "game-theory", def: "A learning dynamic in which each player repeatedly best-responds to the empirical frequency of the opponents' past moves. No equilibrium reasoning is used, yet in many games (zero-sum, potential games) the long-run average play converges to a Nash equilibrium." },
  { term: "Revenue equivalence", topic: "game-theory", def: "A theorem that, under standard assumptions (independent private values, risk-neutral bidders, the item going to the highest valuer, and zero surplus for the lowest type), every auction format yields the seller the <em>same</em> expected revenue — first-price, second-price, all-pay, Dutch, and English alike." },
  { term: "First-price auction", topic: "game-theory", def: "A sealed-bid auction where the highest bidder wins and pays their own bid. Unlike a second-price auction, truthful bidding is not optimal — bidders <em>shade</em> below their value, trading a higher chance of winning against a smaller surplus." },
  { term: "Matrix exponential", topic: "linear-algebra", def: "$e^{At}=I+At+\\tfrac{(At)^2}{2!}+\\cdots$, computed via diagonalization as $P\\,e^{Dt}P^{-1}$. It solves the linear system $\\dot{x}=Ax$ as $x(t)=e^{At}x(0)$, and the eigenvalues' real parts decide its stability." },
  { term: "Phase portrait", topic: "linear-algebra", def: "A picture of a dynamical system's trajectories in state space. For $\\dot{x}=Ax$ the eigenvalues set the shape — inward/outward spirals (complex), nodes, saddles, or centers — and the system is stable exactly when every eigenvalue has negative real part." },
  { term: "Automatic differentiation (autodiff)", topic: "calculus", def: "Computing exact derivatives by applying the chain rule to a program's elementary operations — not symbolic algebra, not finite differences. Forward mode propagates derivatives alongside values (cost scales with inputs); reverse mode walks backward from the output (cost scales with outputs) and is exactly backpropagation." },
  { term: "Dual number", topic: "calculus", def: "A value paired with an infinitesimal part, $a + b\\epsilon$ where $\\epsilon^2 = 0$. Arithmetic on dual numbers carries the chain rule automatically, so evaluating $f(x + \\epsilon)$ returns $f(x) + f'(x)\\,\\epsilon$ — the mechanism behind forward-mode autodiff." },
  { term: "Gaussian mixture model (GMM)", topic: "machine-learning", def: "A density model that treats data as generated by $K$ Gaussian components, each with its own mean, covariance, and mixing weight. Fit by EM, it gives every point a soft cluster membership; k-means is its hard-assignment limit." },
  { term: "Expectation-maximization (EM)", topic: "machine-learning", def: "An iterative algorithm for maximum-likelihood estimation with latent variables. The E-step computes the posterior over the hidden variables given current parameters; the M-step re-estimates parameters as posterior-weighted averages. Powers GMMs, HMMs (Baum-Welch), and k-means (hard EM)." },
  { term: "Responsibility (soft assignment)", topic: "machine-learning", def: "In a mixture model, the posterior probability $r_{ik}$ that component $k$ generated point $i$ — a soft membership in $[0,1]$ summing to 1 over components. The E-step of EM computes it; hardening it to 0/1 recovers k-means." },
  { term: "Bloom filter", topic: "algorithms", def: "A space-efficient probabilistic set: a bit array plus k hash functions. Membership queries have <em>no false negatives</em> but tunable false positives, and items cannot be removed (counting Bloom filters add counters to allow it). Used to guard databases, caches, CDNs, and crawler seen-sets." },
  { term: "Probabilistic data structure", topic: "algorithms", def: "A structure that trades exact answers for large space/time savings via randomization and bounded error — e.g. Bloom filters (set membership), HyperLogLog (distinct-count), Count-Min sketch (frequencies), and MinHash/LSH (similarity)." },
  { term: "Distributional reinforcement learning", topic: "reinforcement-learning", def: "Learning the full distribution of the return $Z(s,a)$ rather than only its mean $Q=\\mathbb{E}[Z]$. It obeys a distributional Bellman equation and is represented by categorical atoms (C51) or quantiles (QR-DQN); the richer target improves representations and enables risk-sensitive control." },
  { term: "Quantile regression", topic: "machine-learning", def: "Regression that predicts a chosen quantile (e.g. the median or 90th percentile) of the target instead of its mean, by minimizing the asymmetric <em>pinball</em> loss. Underlies QR-DQN and conformalized quantile prediction." },
  { term: "Spectral density", topic: "time-series", def: "How a time series' variance is distributed across frequencies — the \"power\" at each frequency. By the Wiener-Khinchin theorem it is the Fourier transform of the autocovariance function; peaks reveal periodic cycles." },
  { term: "Periodogram", topic: "time-series", def: "A data estimate of the spectral density: the squared magnitude of a series' discrete Fourier transform. Tall peaks pinpoint dominant cycles that are hard to spot in the time domain." },
  { term: "Fast Fourier Transform (FFT)", topic: "algorithms", def: "A divide-and-conquer algorithm that computes the discrete Fourier transform of $n$ points in $O(n\\log n)$ instead of $O(n^2)$. The workhorse behind spectral analysis, signal processing, and fast polynomial and integer multiplication." },
  { term: "Delta method", topic: "probability-statistics", def: "A first-order Taylor approximation for the variance and asymptotic distribution of a transformed estimator: $\\operatorname{Var}(g(\\hat\\theta)) \\approx [g'(\\theta)]^2\\operatorname{Var}(\\hat\\theta)$. It supplies standard errors for ratios, logs, and odds; the multivariate form uses the gradient, $\\nabla g^\\top\\Sigma\\nabla g$." },
  { term: "Asymptotic normality", topic: "probability-statistics", def: "The property that an estimator's sampling distribution approaches a normal as the sample size grows, $\\sqrt{n}(\\hat\\theta-\\theta)\\to\\mathcal{N}(0,\\sigma^2)$. It underlies the central limit theorem, maximum-likelihood standard errors, and the delta method, justifying normal-based confidence intervals." },
  { term: "Rate-distortion function", topic: "information-theory", def: "$R(D)$: the minimum bits per symbol needed to reconstruct a source within average distortion $D$, $R(D)=\\min I(X;\\hat X)$ subject to $\\mathbb{E}[d]\\le D$. Convex and decreasing, with $R(0)=H$ — the floor every lossy codec, and a VAE's rate-distortion objective, chases." },
  { term: "Lossy compression", topic: "information-theory", def: "Compression that discards information to save bits, accepting bounded reconstruction error (JPEG, MP3, neural codecs) — unlike lossless coding, which reconstructs exactly. Its fundamental limit is the rate-distortion function." },
  { term: "Price of anarchy", topic: "game-theory", def: "The ratio of the social cost of the <em>worst</em> Nash equilibrium to that of the optimal coordinated outcome. A value of 1 means selfishness is free; a large value means coordination would help a lot. For selfish routing with linear congestion it is exactly 4/3." },
  { term: "Braess's paradox", topic: "game-theory", def: "The counterintuitive fact that adding a road (or capacity) to a congested network can shift it to a new equilibrium where <em>everyone</em> is worse off — a vivid demonstration that selfish equilibria can be inefficient (price of anarchy above 1)." },
  { term: "Conjugate gradient (CG)", topic: "linear-algebra", def: "An iterative method for solving $A\\mathbf{x}=\\mathbf{b}$ with symmetric positive-definite $A$ (or minimizing the matching quadratic) using only matrix-vector products. It steps along $A$-orthogonal (\"conjugate\") directions, reaches the exact solution in at most $n$ steps, and converges fast when $A$ is well-conditioned." },
  { term: "Preconditioning", topic: "linear-algebra", def: "Transforming a linear system $A\\mathbf{x}=\\mathbf{b}$ into an equivalent one with a smaller condition number (e.g. $M^{-1}A\\mathbf{x}=M^{-1}\\mathbf{b}$) so iterative solvers like conjugate gradient converge in far fewer steps. Choosing a good preconditioner $M$ is the craft of large-scale linear solves." },
  { term: "Nash bargaining solution", topic: "game-theory", def: "The division of surplus between two parties that maximizes the product of gains over the disagreement point, $(u_1-d_1)(u_2-d_2)$. It is the unique outcome satisfying Pareto efficiency, symmetry, invariance to affine rescaling, and independence of irrelevant alternatives." },
  { term: "Disagreement point", topic: "game-theory", def: "The payoffs each party receives if negotiation fails — their outside options or threat point $(d_1,d_2)$. It anchors the Nash bargaining solution: a stronger outside option shifts the agreed split in your favor even when the deal itself is unchanged." },
  { term: "Stochastic approximation (Robbins-Monro)", topic: "calculus", def: "A scheme for finding a root or optimum from <em>noisy</em> measurements, $x_{t+1}=x_t-a_t\\,g_t$. It converges when the step sizes satisfy $\\sum a_t=\\infty$ and $\\sum a_t^2<\\infty$ — the 1951 result that is the theoretical foundation of SGD and the reason learning rates decay." },
  { term: "Learning rate schedule", topic: "deep-learning", def: "A rule for varying the step size over training — decay (e.g. $1/t$, cosine), warmup, or warm restarts. Decay lets SGD settle (the Robbins-Monro conditions), while warmup stabilizes the unstable early phase of large-batch training." },
  { term: "Mirror descent", topic: "calculus", def: "A generalization of gradient descent that replaces the Euclidean proximity term with a Bregman divergence from a convex potential $\\psi$, adapting steps to the domain's geometry. With $\\psi=\\tfrac12\\lVert\\cdot\\rVert^2$ it is ordinary gradient descent; with negative entropy on the simplex it becomes multiplicative weights." },
  { term: "Bregman divergence", topic: "calculus", def: "$D_\\psi(x,y)=\\psi(x)-\\psi(y)-\\langle\\nabla\\psi(y),x-y\\rangle$: the gap between a convex $\\psi$ and its tangent plane at $y$. A geometry-aware (asymmetric) \"distance\" underlying mirror descent; squared-Euclidean distance and KL divergence are special cases." },
  { term: "Multiplicative weights", topic: "game-theory", def: "An online-learning and optimization rule that updates a probability vector by scaling each weight by $e^{-\\eta\\,\\text{loss}}$ and renormalizing — the simplex (entropy) case of mirror descent. It powers no-regret learning, boosting (AdaBoost), and fast game-solving." },
  { term: "Mixup", topic: "deep-learning", def: "A data-augmentation method that trains on convex combinations of example pairs and their labels, $\\tilde x=\\lambda x_i+(1-\\lambda)x_j$ and $\\tilde y=\\lambda y_i+(1-\\lambda)y_j$ with $\\lambda\\sim\\mathrm{Beta}(\\alpha,\\alpha)$. It smooths decision boundaries and improves calibration and robustness; <em>cutmix</em> is the patch-pasting variant." },
  { term: "Vicinal risk minimization", topic: "deep-learning", def: "Training to minimize loss over a neighborhood (\"vicinity\") around each data point — drawing nearby virtual examples — instead of only at the observed points (empirical risk). Data augmentation and mixup are instances of it." },
  { term: "Anomaly detection", topic: "machine-learning", def: "Flagging rare, abnormal points (fraud, intrusions, faults), usually unsupervised: model what \"normal\" looks like and score each point's misfit. Methods include Isolation Forest, density models (GMM/KDE, Local Outlier Factor), one-class SVM, and autoencoder reconstruction error." },
  { term: "Isolation Forest", topic: "machine-learning", def: "An anomaly detector that builds random-split trees: outliers lie in sparse regions and get isolated in very few splits, so a short average path length flags them. Fast, near-linear, and needs no density estimate." },
  { term: "Attention sink", topic: "llm", def: "A token (usually the first) that absorbs the excess attention softmax must assign when no position is truly relevant — attention weights sum to 1, so the surplus is dumped somewhere. Retaining sink tokens during KV-cache eviction (StreamingLLM) keeps long-context streaming stable." },
  { term: "Sliding-window attention", topic: "llm", def: "Restricting each token to attend only to the last $W$ tokens, cutting attention cost from $O(n^2)$ to $O(nW)$ and bounding the KV cache. Paired with retained attention sinks, it supports effectively unbounded streaming context." },
  { term: "Martingale", topic: "probability-statistics", def: "A stochastic process whose expected next value given the past equals its current value, $\\mathbb{E}[X_{t+1}\\mid\\text{past}]=X_t$ — the model of a fair game. Random walks and Brownian motion are martingales; a bounded martingale converges almost surely." },
  { term: "Optional stopping theorem", topic: "probability-statistics", def: "Under mild conditions no stopping rule changes a martingale's expected value: $\\mathbb{E}[X_\\tau]=X_0$ for a stopping time $\\tau$. The rigorous reason no betting system beats a fair game in expectation." },
  { term: "f-divergence", topic: "information-theory", def: "A family of distances between distributions, $D_f(P\\Vert Q)=\\mathbb{E}_Q[f(p/q)]$ for a convex $f$ with $f(1)=0$. KL, total variation, Hellinger, $\\chi^2$, and Jensen-Shannon are all instances; all are non-negative, jointly convex, and obey the data-processing inequality." },
  { term: "Hellinger distance", topic: "information-theory", def: "A bounded, symmetric f-divergence from $f(t)=(\\sqrt t-1)^2$: $H^2(P,Q)=\\tfrac12\\int(\\sqrt p-\\sqrt q)^2$. It lies in $[0,1]$ and stays well-behaved where KL blows up (nearly disjoint supports)." },
  { term: "Chi-squared divergence", topic: "information-theory", def: "The f-divergence with $f(t)=(t-1)^2$, giving $\\chi^2(P\\Vert Q)=\\int (p-q)^2/q$. It upper-bounds the KL divergence and underlies goodness-of-fit tests and local (variance-like) approximations of divergences." },
  { term: "Kalman filter", topic: "time-series", def: "The optimal recursive estimator of a hidden state from noisy observations under linear-Gaussian dynamics — a predict-update cycle that is Bayesian filtering for Gaussians. The Kalman gain weights the model prediction against the new measurement by their relative uncertainties." },
  { term: "Particle filter", topic: "time-series", def: "A sequential Monte Carlo state estimator for nonlinear, non-Gaussian systems: represent the belief by weighted samples (\"particles\"), propagate them through the dynamics, reweight by each new measurement, and resample. The Kalman filter's general-purpose successor." },
  { term: "Online algorithm", topic: "algorithms", def: "An algorithm that processes its input piece by piece and must commit to each decision irrevocably, with no view of the future (caching, ski rental, scheduling). Its quality is measured by the competitive ratio against the optimal offline algorithm." },
  { term: "Competitive ratio", topic: "algorithms", def: "The worst-case ratio of an online algorithm's cost to that of the optimal <em>offline</em> algorithm that knew the whole input. \"$c$-competitive\" means never worse than $c$ times optimal; randomization often lowers it (ski rental: 2 deterministic, $e/(e-1)$ randomized)." },
  { term: "Hierarchical reinforcement learning", topic: "reinforcement-learning", def: "RL with temporal abstraction: the agent acts through reusable multi-step sub-behaviors (options/skills) rather than only primitive actions. It shortens the effective horizon, eases long-range credit assignment, and lets learned skills transfer across tasks." },
  { term: "Option (reinforcement learning)", topic: "reinforcement-learning", def: "A temporally-extended action defined by an initiation set, an internal policy, and a termination condition. Choosing among options turns an MDP into a <em>semi-MDP</em>, where each action lasts a variable number of steps." },
  { term: "Energy-based model (EBM)", topic: "deep-learning", def: "A generative model defining $p(x)=e^{-E(x)}/Z$ from a free-form energy network $E(x)$ — low energy means high probability. The partition function $Z$ is intractable, so EBMs are trained by contrastive divergence or score matching (the bridge to diffusion models)." },
  { term: "Partition function", topic: "deep-learning", def: "The normalizing constant $Z=\\int e^{-E(x)}\\,dx$ of an energy-based / Gibbs distribution, summing the unnormalized density over all configurations. It is generally intractable — the central difficulty in training EBMs and undirected graphical models." },
  { term: "Boltzmann distribution", topic: "information-theory", def: "The law $p(x)\\propto e^{-E(x)/T}$ that maximizes entropy for a given expected energy (with temperature $T$). It is the form behind energy-based models, the softmax, simulated annealing, and statistical mechanics." },
  { term: "Neural ODE", topic: "deep-learning", def: "A model that defines its hidden state by a learned ODE $\\frac{dh}{dt}=f(h,t,\\theta)$ and integrates it with an adaptive solver — the continuous limit of a residual network. Depth becomes continuous time; gradients come from the adjoint method in $O(1)$ memory." },
  { term: "Adjoint method", topic: "deep-learning", def: "A way to compute gradients through an ODE solve by integrating a second (\"adjoint\") ODE backward in time, giving constant memory in depth instead of storing every intermediate state. The backbone of training neural ODEs." },
  { term: "Representer theorem", topic: "machine-learning", def: "For a regularized fit over an RKHS, the optimal function is a <em>finite</em> combination of the kernel at the training points, $f(x)=\\sum_i \\alpha_i\\,k(x_i,x)$. It collapses an infinite-dimensional problem to $n$ coefficients — the reason SVMs, kernel ridge regression, and GP regression are computable." },
  { term: "Reproducing kernel Hilbert space (RKHS)", topic: "machine-learning", def: "The function space a positive-definite kernel $k$ implicitly defines, where evaluation acts as an inner product, $f(x)=\\langle f, k(x,\\cdot)\\rangle$. Working in it through kernel evaluations alone is the kernel trick; the representer theorem keeps the optimization finite." },
  { term: "Multi-task learning", topic: "deep-learning", def: "Training one model on several related tasks at once through a shared representation — typically hard parameter sharing (a shared trunk plus task-specific heads) with a combined loss. Each task regularizes the others, improving data efficiency and generalization." },
  { term: "Negative transfer", topic: "deep-learning", def: "When jointly training unrelated or conflicting tasks <em>hurts</em> performance — their gradients pull the shared weights in opposing directions. Mitigated by task weighting, grouping compatible tasks, soft sharing, or gradient surgery (projecting away conflicting gradients)." },
  { term: "Cournot competition", topic: "game-theory", def: "An oligopoly model where firms simultaneously choose output <em>quantities</em>; price falls as total quantity rises. The Nash equilibrium sits between monopoly and perfect competition, approaching the competitive outcome as the number of firms grows." },
  { term: "Bertrand competition", topic: "game-theory", def: "An oligopoly model where firms simultaneously choose <em>prices</em> and buyers take the cheapest. The Bertrand paradox: with identical goods and equal marginal cost, just two firms drive price down to marginal cost and profit to zero." },
  { term: "Oligopoly", topic: "game-theory", def: "A market with a few firms whose decisions affect one another, so strategic (game-theoretic) reasoning applies. Outcomes hinge on the competition variable — quantities (Cournot), prices (Bertrand), or sequential moves (Stackelberg)." },
  { term: "Calculus of variations", topic: "calculus", def: "Optimization over functions: find the $y(x)$ minimizing a functional $J[y]=\\int L(x,y,y')\\,dx$. Its stationarity condition is the Euler-Lagrange equation. It underlies least action, optimal control, geodesics, and the maximum-entropy derivation." },
  { term: "Euler-Lagrange equation", topic: "calculus", def: "The stationarity condition of a functional, $\\frac{\\partial L}{\\partial y}-\\frac{d}{dx}\\frac{\\partial L}{\\partial y'}=0$ — the function-space analogue of setting the gradient to zero. Solving it yields the optimal curve (straight lines, the brachistochrone, the equations of motion)." },
  { term: "Perron-Frobenius theorem", topic: "linear-algebra", def: "An irreducible matrix with nonnegative entries has a real eigenvalue $\\lambda^\\ast$ (its spectral radius) that is strictly largest in magnitude and simple, with an all-positive eigenvector. It is the basis of PageRank, Markov-chain stationary distributions, and the convergence of power iteration." },
  { term: "Irreducible matrix", topic: "linear-algebra", def: "A nonnegative matrix whose directed graph is strongly connected — every state reaches every other. Irreducibility is the condition under which the Perron-Frobenius theorem and a unique Markov-chain stationary distribution hold." },
  { term: "Natural gradient", topic: "information-theory", def: "The gradient preconditioned by the inverse Fisher information, $F^{-1}\\nabla L$ — steepest descent in distribution space (per unit KL), invariant to how the model is parameterized. It underlies natural policy gradients, TRPO, and K-FAC." },
  { term: "Information geometry", topic: "information-theory", def: "Treating a family of probability distributions as a curved manifold whose metric is the Fisher information; the KL divergence between nearby models is $\\tfrac12 d\\theta^\\top F\\,d\\theta$ to second order. It is the basis of the natural gradient." },
  { term: "Trust region", topic: "calculus", def: "An optimization scheme that limits each step to a region where a local model is trustworthy — e.g. bounding the KL change of a policy (TRPO). It converts a hard global problem into a sequence of safe local steps." },
  { term: "Entropy rate", topic: "information-theory", def: "The long-run per-symbol entropy of a process with memory, $H=\\lim_n\\tfrac1n H(X_1,\\dots,X_n)=\\lim_n H(X_n\\mid\\text{past})$. It falls below the marginal entropy when context predicts; it is the compressibility floor and the limit a language model's perplexity approaches from above." },
  { term: "Asymptotic equipartition property (AEP)", topic: "information-theory", def: "For a long i.i.d. sequence, almost all probability concentrates on about $2^{nH}$ nearly-equally-likely \"typical\" sequences. This is why a source compresses to roughly $H$ bits per symbol — the proof idea behind the source coding theorem." },
  { term: "Conditional entropy", topic: "information-theory", def: "$H(Y\\mid X)=\\mathbb{E}[H(Y\\mid X{=}x)]$: the average remaining uncertainty about $Y$ once $X$ is known. It obeys the chain rule $H(X,Y)=H(X)+H(Y\\mid X)$, and mutual information is $I(X;Y)=H(Y)-H(Y\\mid X)$." },
  { term: "Empirical Bayes", topic: "probability-statistics", def: "A method that estimates the prior distribution from the data itself, then applies Bayesian shrinkage — pulling each individual estimate toward the global mean, more so for the noisy ones. A data-driven approximation to fully hierarchical Bayes." },
  { term: "James-Stein estimator", topic: "probability-statistics", def: "A shrinkage estimator that, when estimating three or more means at once, has strictly lower total squared error than the raw sample means for <em>every</em> true value — the \"Stein paradox.\" Evidence that pooling information across estimates beats estimating each alone." },
  { term: "Shrinkage", topic: "probability-statistics", def: "Pulling parameter estimates toward a central value (a common mean or zero), trading a little bias for a large cut in variance. It underlies empirical Bayes, ridge and lasso regularization, and hierarchical models." },
  { term: "Dynamic time warping (DTW)", topic: "time-series", def: "A dynamic-programming alignment of two time series that may run at different speeds: it matches each point to one or more of the other to minimize total distance, $D(i,j)=d(a_i,b_j)+\\min(D(i{-}1,j),D(i,j{-}1),D(i{-}1,j{-}1))$. A strong classification baseline (1-NN+DTW); kin to edit distance." },
  { term: "Edit distance", topic: "algorithms", def: "The minimum number of insertions, deletions, and substitutions to turn one string into another (Levenshtein distance), computed by a classic $O(nm)$ dynamic program. The discrete cousin of dynamic time warping and the basis of spell-checkers and sequence alignment." },
  { term: "Skip list", topic: "algorithms", def: "A probabilistic balanced search structure: a sorted linked list with coin-flip \"express lanes\" that give $O(\\log n)$ expected search, insert, and delete without rotations. Used in Redis and LevelDB; a simple, concurrency-friendly alternative to balanced BSTs." },
  { term: "Randomized algorithm", topic: "algorithms", def: "An algorithm that makes random choices, so its behavior varies run to run. Las Vegas variants are always correct with random runtime; Monte Carlo variants run in fixed time with a small error probability. They are often simpler or faster than the best deterministic method." },
  { term: "Binary search tree (BST)", topic: "algorithms", def: "A tree where each node's left subtree holds smaller keys and its right subtree larger ones, giving $O(\\log n)$ search/insert/delete when balanced — and $O(n)$ when it degenerates, which self-balancing variants (AVL, red-black) and skip lists prevent." },
  { term: "Successor representation (SR)", topic: "reinforcement-learning", def: "A predictive state representation $M(s,s')=\\mathbb{E}[\\sum_t\\gamma^t\\mathbb{1}(s_t=s')]$ — the expected discounted future occupancy of each state. Value factorizes as $V=Mr$, so a changed reward needs no relearning, just re-multiplication. It bridges model-free and model-based RL." },
  { term: "Successor features", topic: "reinforcement-learning", def: "The function-approximation generalization of the successor representation: predict expected discounted future state-<em>features</em> instead of per-state visits, making value a linear function of a reward-weight vector. Enables transfer across tasks that share dynamics in deep RL." },
  { term: "Convex conjugate (Fenchel transform)", topic: "calculus", def: "$f^\\ast(y)=\\sup_x(\\langle y,x\\rangle-f(x))$: a convex function re-described by its supporting-line slopes. Always convex, and for a closed convex $f$ it is an involution, $f^{\\ast\\ast}=f$. The engine of Lagrangian/Fenchel duality, mirror descent, and the Legendre transform." },
  { term: "Fenchel-Young inequality", topic: "calculus", def: "$f(x)+f^\\ast(y)\\ge\\langle x,y\\rangle$ for any convex $f$ and its conjugate $f^\\ast$, with equality exactly when $y$ is a subgradient of $f$ at $x$. The relation that makes $\\nabla f$ and $\\nabla f^\\ast$ inverse maps." },
  { term: "Log-sum-exp", topic: "deep-learning", def: "$\\mathrm{LSE}(x)=\\log\\sum_i e^{x_i}$: a smooth (\"soft\") maximum, the convex conjugate of negative entropy and the log-normalizer of the softmax. Computed stably by subtracting the max before exponentiating." },
  { term: "Envelope theorem", topic: "calculus", def: "For a value function $V(\\theta)=\\max_x f(x,\\theta)$, the derivative is $\\frac{dV}{d\\theta}=\\frac{\\partial f}{\\partial\\theta}$ evaluated at the optimum — the optimizer's own movement contributes nothing (the first-order condition kills it). It underlies shadow prices, Hotelling/Shephard's lemmas, and policy gradients." },
  { term: "Danskin's theorem", topic: "calculus", def: "The envelope theorem for a maximum: a (sub)gradient of $\\max_x f(x,\\theta)$ in $\\theta$ is $\\frac{\\partial f}{\\partial\\theta}$ at a maximizer. It justifies differentiating through the inner max in minimax and adversarial training (adversarial examples, GAN inner loops)." },
  { term: "Partial dependence plot (PDP)", topic: "machine-learning", def: "A global interpretability plot: sweep one feature across its range, average the model's prediction over the data, and trace that feature's marginal effect. ICE plots show the per-instance curves underneath; both can mislead when features are correlated." },
  { term: "Permutation importance", topic: "machine-learning", def: "A model-agnostic measure of feature importance: shuffle one feature's column and see how far accuracy drops. A large drop means the model leaned on that feature. Correlated features can dilute or distort the scores." },
  { term: "LIME", topic: "machine-learning", def: "Local Interpretable Model-agnostic Explanations: fit a simple interpretable model (usually linear) to the black box's predictions in a small neighborhood of one input, revealing which features drove that particular prediction." },
  { term: "Schur complement", topic: "linear-algebra", def: "For a block matrix $\\begin{bmatrix}A&B\\\\C&D\\end{bmatrix}$, the Schur complement of $D$ is $A-BD^{-1}C$ — what remains of $A$ after block-eliminating $D$. It drives block inversion and determinants, equals the conditional covariance of a Gaussian, and tests block positive-definiteness." },
  { term: "Kronecker product", topic: "linear-algebra", def: "The block product $A\\otimes B$ that tiles a copy of $B$ scaled by each entry of $A$, giving an $(mp)\\times(nq)$ matrix. It satisfies $\\mathrm{vec}(AXB^\\top)=(B\\otimes A)\\,\\mathrm{vec}(X)$ and models structured/separable operators (e.g. the K-FAC approximation of the Fisher matrix)." },
  { term: "Multi-head latent attention (MLA)", topic: "llm", def: "A KV-cache compression (DeepSeek-V2): cache one low-rank latent per token and reconstruct per-head keys and values via up-projections that fold into the query and output maps. It keeps full multi-head quality at roughly multi-query cache size." },
  { term: "Grouped-query attention (GQA)", topic: "llm", def: "An attention variant where several query heads share one key/value head, interpolating between full multi-head and multi-query attention. It shrinks the KV cache with little quality loss; used in Llama-2/3 and many production models." },
  { term: "Multi-query attention (MQA)", topic: "llm", def: "An attention variant where all query heads share a single key/value head, cutting the KV cache to a fraction of multi-head attention's. Fast at inference but can cost some quality — which grouped-query and latent attention recover." },
  { term: "Copula", topic: "probability-statistics", def: "A joint CDF on the unit square with uniform marginals that encodes the dependence structure of several variables. By Sklar's theorem any joint distribution is a copula glued onto its marginals, so dependence can be modeled separately from each variable's own law." },
  { term: "Tail dependence", topic: "probability-statistics", def: "The tendency of extreme values of two variables to occur together. The Gaussian copula has zero tail dependence (extremes decouple); the $t$- and Clayton/Gumbel copulas retain it. Underestimating it (Gaussian-copula CDO pricing) understated joint-crash risk before 2008." },
  { term: "Probability integral transform", topic: "probability-statistics", def: "Passing a continuous random variable through its own CDF, $F(X)$, yields a $\\mathrm{Uniform}(0,1)$ variable. It is the bridge to copulas (making marginals uniform) and underlies inverse-transform sampling and many goodness-of-fit tests." },
  { term: "Change-point detection", topic: "time-series", def: "Finding the times at which a series' generating distribution shifts abruptly (mean, variance, or regime). Online methods (CUSUM) alarm as soon as possible after a change; offline methods segment the whole series by penalized dynamic programming (PELT, binary segmentation)." },
  { term: "CUSUM", topic: "time-series", def: "The cumulative-sum change detector: accumulate the log-likelihood ratio of \"changed\" vs \"unchanged\" and reset at zero, $S_t=\\max(0,S_{t-1}+\\ell_t)$, alarming when $S_t$ crosses a threshold. Page's test minimizes detection delay for a given false-alarm rate." },
  { term: "Sequential probability ratio test (SPRT)", topic: "probability-statistics", def: "Wald's sequential test: accumulate the log-likelihood ratio as data arrive and stop the moment it crosses an upper or lower bound (accept / reject), otherwise keep sampling. It reaches a decision with fewer samples on average than any fixed-size test and underlies CUSUM and sequential A/B testing." },
  { term: "Hindsight experience replay (HER)", topic: "reinforcement-learning", def: "A trick for sparse-reward goal-conditioned RL: after an episode fails to reach goal $g$ but ends at $g'$, relabel its transitions as a success for $g'$. Goal-conditioned values turn that into a usable signal, so every episode teaches something even when the real goal was missed." },
  { term: "Goal-conditioned RL", topic: "reinforcement-learning", def: "Reinforcement learning where the policy and value function take the goal as an extra input, $\\pi(a\\mid s,g)$ and $Q(s,a,g)$, so one agent pursues many goals and experience transfers across them. It is the setting that makes hindsight relabeling possible." },
  { term: "Sparse reward", topic: "reinforcement-learning", def: "A reward signal that is zero almost everywhere and nonzero only on rare success, leaving little gradient to learn from. It drives much of exploration research — intrinsic motivation, reward shaping, and hindsight relabeling." },
  { term: "Consistent hashing", topic: "algorithms", def: "A distributed-hashing scheme that maps keys and servers onto a ring, giving each key to the next server clockwise. Adding or removing a server moves only about $K/N$ of the $K$ keys instead of remapping everything — the backbone of distributed caches and databases." },
  { term: "Virtual nodes", topic: "algorithms", def: "Hashing each server to many points on a consistent-hashing ring instead of one, so the arc sizes even out and a failed server's load scatters across many peers rather than landing entirely on a single neighbor." },
  { term: "Rolling hash", topic: "algorithms", def: "A hash of a sliding window that updates in $O(1)$ as the window moves — add the entering element, subtract the leaving one. It powers Rabin-Karp substring search, content-defined chunking, and rsync-style diffing." }
];
